    game.tisNext = function() {
   if (game.tisQueue.length === 0 || game.isTising) {
     return;
   }
   game.isTising = true;
   const [str, time = 3500] = game.tisQueue.shift();
   game.tis(str,time);
   setTimeout(function() {
     game.isTising = false;
     game.tisNext();
   }, time);
 };

 game.tisSequence = function(...items) {
   game.tisQueue = [];
   game.isTising = false;
   game.tisQueue.push(...items);
   game.tisNext();
 };
     
