                       if(lib.character[i][4].some(item => item.includes('杂耍能力：S'))&&!window.tujian.杂耍能力S.includes(i))window.tujian.杂耍能力S.push(i);
                       if(lib.character[i][4].some(item => item.includes('生存能力：A'))&&!window.tujian.生存能力A.includes(i))window.tujian.生存能力A.push(i);
                       if(lib.character[i][4].some(item => item.includes('攻击强度：A'))&&!window.tujian.攻击强度A.includes(i))window.tujian.攻击强度A.push(i);
                       if(lib.character[i][4].some(item => item.includes('辅助能力：A'))&&!window.tujian.辅助能力A.includes(i))window.tujian.辅助能力A.push(i);
                       if(lib.character[i][4].some(item => item.includes('杂耍能力：A'))&&!window.tujian.杂耍能力A.includes(i))window.tujian.杂耍能力A.push(i);
                       if(lib.character[i][4].some(item => item.includes('生存能力：B'))&&!window.tujian.生存能力B.includes(i))window.tujian.生存能力B.push(i);
                       if(lib.character[i][4].some(item => item.includes('攻击强度：B'))&&!window.tujian.攻击强度B.includes(i))window.tujian.攻击强度B.push(i);
                       if(lib.character[i][4].some(item => item.includes('辅助能力：B'))&&!window.tujian.辅助能力B.includes(i))window.tujian.辅助能力B.push(i);
                       if(lib.character[i][4].some(item => item.includes('杂耍能力：B'))&&!window.tujian.杂耍能力B.includes(i))window.tujian.杂耍能力B.push(i);
                       if(lib.character[i][4].some(item => item.includes('生存能力：C'))&&!window.tujian.生存能力C.includes(i))window.tujian.生存能力C.push(i);
                       if(lib.character[i][4].some(item => item.includes('攻击强度：C'))&&!window.tujian.攻击强度C.includes(i))window.tujian.攻击强度C.push(i);
                       if(lib.character[i][4].some(item => item.includes('辅助能力：C'))&&!window.tujian.辅助能力C.includes(i))window.tujian.辅助能力C.push(i);
                       if(lib.character[i][4].some(item => item.includes('杂耍能力：C'))&&!window.tujian.杂耍能力C.includes(i))window.tujian.杂耍能力C.push(i);
