// 模板注册
for(var i in bag){
    var item=bag[i];
    lib.clsk_bag[i]=item;
};

//4. 背包工具

//药品消耗条件
game.clskItemYaoFilter=function(){
   return (lib.config.mode=="boss"||lib.config.mode=="肉鸽模式")&&game.me;
}

// 背包索引重建
game.clskRebuildBagIndex = function() {
    const newBag = {};
    let newIndex = 0;
    for (let key in lib.config.clsk_bag) {
        if (lib.config.clsk_bag[key]) {
            newBag[newIndex] = lib.config.clsk_bag[key];
            newIndex++;
        }
    }
    // 同步新的背包数据和数量
    lib.config.clsk_bag = newBag;
    lib.config.clsk_bag_num = newIndex;
    game.saveConfig('clsk_bag', lib.config.clsk_bag);
    game.saveConfig('clsk_bag_num', lib.config.clsk_bag_num);
    return newIndex;
};


//检测背包中未装备的某种物品的数量
game.clskGetItemUsableCount=function(itemName) {
    if (!itemName || !lib.clsk_bag[itemName]) {
        return 0;
    }
    const bagItems = lib.config.clsk_bag;
    let totalCount = 0;
    for (const key in bagItems) {
        const item = bagItems[key];
        if (!item) continue;
        if (item.name === itemName && !item.isEquipped) {
            totalCount += item.num;
        }
    }
    return totalCount;
};

// 检测背包中某种物品的总数量（包括已装备）
game.clskGetItemTotalCount = function(itemName) {
    if (!itemName || !lib.clsk_bag[itemName]) {
        return 0;
    }
    const bagItems = lib.config.clsk_bag;
    let totalCount = 0;
    for (const key in bagItems) {
        const item = bagItems[key];
        if (!item) continue;
        if (item.name === itemName) {
            totalCount += item.num;
        }
    }
    return totalCount;
};

//获得物品
game.clskGainItem=function(name,num,ext_name,ext_type,ext_canLay,ext_info,ext_func){
    const itemTemplate = lib.clsk_bag[name];
    if(!itemTemplate) {
        return false;
    }
    if(ext_name===undefined) ext_name=itemTemplate.name;
    const items=lib.config.clsk_bag;
    const stackMax = itemTemplate.stackMax || 99;
    let remainNum = num;

    // 优先叠加已有可堆叠格子
    for(const i in items){
        if(!items[i]) continue;
        const item=items[i];
        if(item.name === name && item.canLay && item.num < stackMax && !item.isEquipped){
            const addNum = Math.min(remainNum, stackMax - item.num);
            item.num += addNum;
            remainNum -= addNum;
            if(remainNum <= 0) break;
        }
    }

    // 剩余数量开新格子
    while(remainNum > 0){
        if (lib.config.clsk_bag_num >= lib.config.clsk_bag_max) {
            break;
        }
        const newNum = Math.min(remainNum, stackMax);
        const newItem={
            name:name,
            num:newNum,
            type:itemTemplate.type,
            canLay:itemTemplate.canLay,
            ext_name:ext_name,
            stackMax: stackMax,
            isEquipped: false,
            equippedTo: null,
            equipSlot: itemTemplate.equipSlot,
            isTwoHanded: itemTemplate.isTwoHanded
        };
        if(itemTemplate.consume_num!==undefined) newItem.consume_num=itemTemplate.consume_num;
        if(ext_type!==undefined) newItem.type=ext_type;
        if(ext_canLay!==undefined) newItem.canLay=ext_canLay;
        if(ext_info!==undefined) newItem.ext_info=ext_info;
        if(ext_func!==undefined) newItem.ext_func=ext_func;

        lib.config.clsk_bag[lib.config.clsk_bag_num] = newItem;
        lib.config.clsk_bag_num += 1;
        remainNum -= newNum;
    }
    game.saveConfig('clsk_bag', lib.config.clsk_bag);
    game.saveConfig('clsk_bag_num', lib.config.clsk_bag_num);
    game.clskUpdateBagTitle();
    if(remainNum > 0) {
        const gainNum = num - remainNum;
        game.tis(gainNum > 0 ? `背包已满，${itemTemplate.name}仅获得${gainNum}个` : '背包已满，无法获得物品！');
        return false;
    } else {
        game.tis(`获得了${itemTemplate.name}×${num}`);
        return true;
    }
};

// 按名称扣除物品
game.clskLoseItem=function(itemName,num,noTip){
    const itemTemplate = lib.clsk_bag[itemName];
    if (!itemTemplate) return false;

    var items=lib.config.clsk_bag;
    var needLose=num;
    var total=0;
    for(var i in items){
        if(items[i] && items[i].name === itemName && !items[i].isEquipped){
            total+=items[i].num;
        }
    }
    if(total<needLose){
        if(!noTip) game.tis(`${itemTemplate.name}数量不足`);
        return false;
    }
    for(var i in items){
        if(needLose<=0) break;
        var item=items[i];
        if(!item || item.name !== itemName || item.isEquipped) continue;

        if(item.num<=needLose){
            needLose-=item.num;
            delete items[i];
        }else{
            item.num-=needLose;
            needLose=0;
        }
    }
    game.clskRebuildBagIndex();
    game.clskUpdateBagTitle();
    if(!noTip) game.tis(`失去了${itemTemplate.name}×${num}`);
    game.clskRenderBagItems(document.querySelector('.clsk_bag_tabButton.active')?.dataset.type || 'all');
    return true;
};

// 按ID扣除物品
game.clskLoseItem2=function(itemId,num,noTip){
    var item=lib.config.clsk_bag[itemId];
    if(!item){
        game.tis('物品不存在，扣除失败');
        return false;
    }
    if(item.isEquipped){
        game.tis('该物品已被装备，请先卸下后再操作！');
        return false;
    }
    if(item.num<num){
        return false;
    }
    const itemTemplate = lib.clsk_bag[item.name];
    item.num-=num;
    if(item.num<=0){
        delete lib.config.clsk_bag[itemId];
    }
    game.clskRebuildBagIndex();
    game.clskUpdateBagTitle();
    if(!noTip && itemTemplate) game.tis(`失去了${itemTemplate.name}×${num}`);
    game.clskRenderBagItems(document.querySelector('.clsk_bag_tabButton.active')?.dataset.type || 'all');
    return true;
};

// 清除幽灵物品（测试用）
game.clskCleanGhostItems = function() {
    var items = lib.config.clsk_bag;
    var cleanedCount = 0;
    for (var key in items) {
        var item = items[key];
        if (!item || (!lib.clsk_bag[item.name] && !item.isEquipped)) {
            delete items[key];
            cleanedCount++;
        }
    }
    var actualCount = 0;
    for (var key in items) {
        if (items[key]) actualCount++;
    }
    lib.config.clsk_bag_num = actualCount;

    game.saveConfig('clsk_bag', items);
    game.saveConfig('clsk_bag_num', actualCount);
    if (game.clskRenderBagItems) {
        game.clskRenderBagItems(document.querySelector('.clsk_bag_tabButton.active')?.dataset.type || 'all');
    }
    game.tis(`清理了 ${cleanedCount} 个幽灵物品，当前占用 ${actualCount} 格`);
};

// 5. 装备系统核心方法

//适配皮肤
game.clskgetBaseCharId=function(charId) {
    if (!charId) return '';
    let baseId = charId;
    if (baseId.startsWith("gz_")) {
        baseId = baseId.slice(3);
    }
    baseId = baseId.replace(/\d+$/, '');
    return baseId;
}

//适配皮肤
game.clskmigrateSkinEquipData=function() {
    const oldEquipData = lib.clsk_character_equip;
    const newEquipData = {};
    for (const charId in oldEquipData) {
        const baseId = game.clskgetBaseCharId(charId);
        const equipData = oldEquipData[charId];
        newEquipData[baseId] = { ...equipData, ...(newEquipData[baseId] || {}) };
    }
    lib.clsk_character_equip = newEquipData;
    lib.config.clsk_equip_data = JSON.parse(JSON.stringify(newEquipData));
    game.saveConfig('clsk_equip_data', lib.config.clsk_equip_data);
}

game.clskmigrateSkinEquipData();


//刷新标题数量
game.clskUpdateBagTitle = function() {
    const titleElement = document.getElementById('clsk_bag_title');
    if (!titleElement) return;
    let actualCount = 0;
    for (let key in lib.config.clsk_bag) {
        if (lib.config.clsk_bag[key]) actualCount++;
    }
    titleElement.textContent = `错乱时空 - 背包 (${actualCount}/${lib.config.clsk_bag_max})`;
};

// 弹出武将选择列表
game.clskShowCharacterSelectList = function(equipItem) {
    if (!equipItem) {
        return;
    }
    if (!lib.characterPack || !lib.characterPack['错乱时空'] || Object.keys(lib.characterPack['错乱时空']).length === 0) {
        return;
    }

    const charPack = lib.characterPack['错乱时空'];
    var charIds = Object.keys(charPack);
    charIds = charIds.filter(id=>!lib.character[id][4].includes('boss')&&!lib.character[id][4].includes('forbidai')&&!lib.character[id][4].includes('unseen')&&!lib.character[id][4].includes('bossallowed'));
    const cardWidth = 100;    // 卡片宽度
    const cardMargin = 15;    // 卡片间距
    const cardsPerRow = 9;    // 每行显示9个卡片
    const titleHeight = 60;   // 标题高度（含margin）

    // 1. 创建遮罩层
    const bg = document.createElement('div');
    bg.style.position = 'fixed';
    bg.style.top = '0';
    bg.style.left = '0';
    bg.style.width = '100%';
    bg.style.height = '100%';
    bg.style.background = 'rgba(0, 0, 0, 0.9)';
    bg.style.zIndex = '99999';
    bg.style.display = 'flex';
    bg.style.alignItems = 'center';
    bg.style.justifyContent = 'center';
    document.body.appendChild(bg);

    // 2. 创建弹窗主体
    const selectBox = document.createElement('div');
    selectBox.style.position = 'relative';
    selectBox.style.width = '90%';
    selectBox.style.maxWidth = '1200px';
    selectBox.style.minWidth = '300px';
    selectBox.style.minHeight = '300px';
    selectBox.style.maxHeight = '80vh';
    selectBox.style.padding = '20px';
    selectBox.style.background = '#1a1a1a';
    selectBox.style.border = '2px solid #ffd700';
    selectBox.style.borderRadius = '8px';
    selectBox.style.boxShadow = '0 0 20px rgba(255,215,0,0.5)';
    selectBox.style.overflowY = 'auto';
    selectBox.style.boxSizing = 'border-box';
    bg.appendChild(selectBox);

    // 3. 弹窗标题
    const title = document.createElement('h3');
    title.innerHTML = `选择要装备【${lib.clsk_bag[equipItem.name]?.name || equipItem.ext_name}】的武将`;
    title.style.color = '#ffd700';
    title.style.fontFamily = 'lishu';
    title.style.fontSize = '20px';
    title.style.margin = '0 0 20px 0';
    title.style.textAlign = 'center';
    selectBox.appendChild(title);

    // 计算卡片网格的总宽度，用于居中
    const gridTotalWidth = cardsPerRow * (cardWidth + cardMargin) - cardMargin;
    // 计算左右边距，让网格居中
    const gridMarginX = `calc(50% - ${gridTotalWidth / 2}px)`;

    // 4. 遍历生成武将卡片，手动计算位置
    charIds.forEach((charId, index) => {
        const charName = get.translation(charId) || charId;

        // 计算当前卡片的行和列
        const row = Math.floor(index / cardsPerRow);
        const col = index % cardsPerRow;

        // 计算卡片的绝对位置
        // x坐标：列位置 + 左边距（居中）
        const x = col * (cardWidth + cardMargin);
        // y坐标：行位置 + 标题高度（避免遮挡）
        const y = row * (cardWidth + cardMargin + 20) + titleHeight;

        // 武将卡片容器 - 使用了绝对定位
        const charCard = document.createElement('div');
        charCard.style.position = 'absolute';
        charCard.style.left = x + 'px';
        charCard.style.top = y + 'px';
        charCard.style.width = cardWidth + 'px';
        charCard.style.height = 'auto';
        charCard.style.cursor = 'pointer';
        charCard.style.padding = '10px';
        charCard.style.border = '2px solid #666';
        charCard.style.borderRadius = '6px';
        charCard.style.background = 'rgba(50,50,50,0.9)';
        charCard.style.boxSizing = 'border-box';
        charCard.style.transition = 'all 0.2s';

        // hover效果
        charCard.onmouseenter = function() {
            this.style.borderColor = '#ffd700';
            this.style.background = 'rgba(70,70,70,0.9)';
            this.style.transform = 'translateY(-3px)';
        };
        charCard.onmouseleave = function() {
            this.style.borderColor = '#666';
            this.style.background = 'rgba(50,50,50,0.9)';
            this.style.transform = 'none';
        };

        // 武将图片
        const charImg = document.createElement('img');
        charImg.src = `extension/错乱时空/${charId}.jpg`;
        charImg.style.width = '80px';
        charImg.style.height = '80px';
        charImg.style.objectFit = 'cover';
        charImg.style.borderRadius = '4px';
        charImg.style.border = '1px solid #ffd700';
        charImg.style.display = 'block';
        charImg.style.margin = '0 auto';
        charImg.onerror = function() {
            this.src = 'extension/错乱时空/默认武将.jpg';
        };
        charCard.appendChild(charImg);

        // 武将名称
        const charNameText = document.createElement('p');
        charNameText.innerHTML = charName;
        charNameText.style.color = '#fff';
        charNameText.style.fontFamily = 'lishu';
        charNameText.style.fontSize = '14px';
        charNameText.style.margin = '8px 0 0 0';
        charNameText.style.textAlign = 'center';
        charNameText.style.whiteSpace = 'nowrap';
        charNameText.style.overflow = 'hidden';
        charNameText.style.textOverflow = 'ellipsis';
        charNameText.style.width = '100%';
        charCard.appendChild(charNameText);

        // 点击事件
        charCard.onclick = function() {
            const charData = { name: charName };
            game.clskEquipToCharacter(equipItem, charId, charData);
            document.body.removeChild(bg);
        };

        // 添加到弹窗
        selectBox.appendChild(charCard);
    });

    // 5. 点击遮罩层关闭
    bg.onclick = function(e) {
        if (e.target === bg) {
            document.body.removeChild(bg);
        }
    };
};

// 装备到武将
game.clskEquipToCharacter = function(equipItem, charId, charData) {
    const baseEquip = lib.clsk_bag[equipItem.name];
    if(!baseEquip) {
        return false;
    }
    const bagItem = lib.config.clsk_bag[equipItem.id];
    if(!bagItem) {
        return false;
    }
    if(bagItem.isEquipped) {
        return false;
    }

    const equipSlot = baseEquip.equipSlot;
    const isTwoHanded = baseEquip.isTwoHanded;
    // 初始化武将装备槽
    if(!lib.clsk_character_equip[charId]) {
        lib.clsk_character_equip[charId] = {};
    }
    const charEquip = lib.clsk_character_equip[charId];
    const charName = charData?.name || charId;
    let unequipSuccess = true;
    if(isTwoHanded) {
        // 双手武器：强制卸下主副手所有装备
        TWO_HAND_OCCUPY_SLOTS.forEach(slot => {
            if(charEquip[slot] && !game.clskUnequipBySlot(charId, slot, true)) {
                unequipSuccess = false;
            }
        });
    } else if(equipSlot === 'mainHand' || equipSlot === 'offHand') {
        // 单手武器：先卸下已装备的双手武器
        if(charEquip.mainHand?.isTwoHanded && !game.clskUnequipBySlot(charId, 'mainHand', true)) {
            unequipSuccess = false;
        }
        // 再卸下当前目标栏位的装备
        if(charEquip[equipSlot] && !game.clskUnequipBySlot(charId, equipSlot, true)) {
            unequipSuccess = false;
        }
    } else {
        // 其他部位：卸下当前栏位装备
        if(charEquip[equipSlot] && !game.clskUnequipBySlot(charId, equipSlot, true)) {
            unequipSuccess = false;
        }
    }
    if(!unequipSuccess) {
        return false;
    }

    // 写入新装备数据
    charEquip[equipSlot] = {
        bagItemId: equipItem.id,
        equipName: equipItem.name,
        extName:baseEquip.name,
        equipSlot: equipSlot,
        isTwoHanded: isTwoHanded
    };

    // 标记背包物品装备状态
    bagItem.isEquipped = true;
    bagItem.equippedTo = {
        charId: charId,
        charName: charName,
        equipSlot: equipSlot,
        slotName: CLSK_EQUIP_SLOTS[equipSlot]
    };
    lib.config.clsk_equip_data = JSON.parse(JSON.stringify(lib.clsk_character_equip));
    game.saveConfig('clsk_equip_data', lib.config.clsk_equip_data);
    game.saveConfig('clsk_bag', lib.config.clsk_bag);
    game.clskRenderBagItems(document.querySelector('.clsk_bag_tabButton.active')?.dataset.type || 'all');
    game.tis(`成功将【${baseEquip.name}】装备给【${charName}】的【${CLSK_EQUIP_SLOTS[equipSlot]}】！`);
    return true;
};

//按栏位卸下装备
game.clskUnequipBySlot = function(charId, slot, isAutoReplace) {
    const charEquip = lib.clsk_character_equip[charId];
    if(!charEquip || !charEquip[slot]) {
        return false;
    }

    const equipData = charEquip[slot];
    const bagItemId = equipData.bagItemId;
    const bagItem = lib.config.clsk_bag[bagItemId];
    if(bagItem) {
        bagItem.isEquipped = false;
        bagItem.equippedTo = null;
    }
    delete charEquip[slot];
    if(Object.keys(charEquip).length === 0) {
        delete lib.clsk_character_equip[charId];
    }
    lib.config.clsk_equip_data = JSON.parse(JSON.stringify(lib.clsk_character_equip));
    game.saveConfig('clsk_equip_data', lib.config.clsk_equip_data);
    game.saveConfig('clsk_bag', lib.config.clsk_bag);
    if(!isAutoReplace) {
        game.tis(`成功将【${equipData.extName}】从【${CLSK_EQUIP_SLOTS[slot]}】卸下！`);
    }
    return true;
};

// 按装备名字卸下装备
game.clskUnequipFromCharacter = function(equipItem) {
    if(!equipItem.isEquipped || !equipItem.equippedTo) {
        return false;
    }

    const charId = equipItem.equippedTo.charId;
    const equipSlot = equipItem.equippedTo.equipSlot;
    const charEquip = lib.clsk_character_equip[charId];
    if(!charEquip || !charEquip[equipSlot] || charEquip[equipSlot].bagItemId !== equipItem.id) {
        const bagItem = lib.config.clsk_bag[equipItem.id];
        if(bagItem) {
            bagItem.isEquipped = false;
            bagItem.equippedTo = null;
            game.saveConfig('clsk_bag', lib.config.clsk_bag);
        }
        game.clskRenderBagItems(document.querySelector('.clsk_bag_tabButton.active')?.dataset.type || 'all');
        return false;
    }
    const result = game.clskUnequipBySlot(charId, equipSlot, false);
    if(result) {
        game.clskRenderBagItems(document.querySelector('.clsk_bag_tabButton.active')?.dataset.type || 'all');
    }
    return result;
};

