// 渲染背包物品
game.clskRenderBagItems = function(type) {
    const rarityColors = {
        common: '#FFFFFF',
        uncommon: '#4CAF50',
        rare: '#1E90FF',
        epic: '#9370DB',
        legendary: '#FFD700',
        mythic: '#FF4444'
    };

    const grid = document.getElementById('clsk_bag_grid');
    if (!grid) return;
    grid.innerHTML = '';

    let itemList = [];
    for (let id in lib.config.clsk_bag) {
        const item = lib.config.clsk_bag[id];
        if (!item) continue;
        if (type === 'all' || item.type === type) {
            itemList.push({ id, ...item });
        }
    }

    itemList.forEach(item => {
        const baseItem = lib.clsk_bag[item.name];
        if (!baseItem) return;

        const slot = document.createElement('div');
        slot.className = 'clsk_bag_item_slot';
        const rarity = baseItem.rarity || 'common';
        slot.style.cssText = `
            border: 3px solid ${rarityColors[rarity]} !important;
            box-shadow: 0 0 12px ${rarityColors[rarity]} !important;
            box-sizing: border-box !important;
            padding: 2px !important;
            position: relative !important;
        `;

        const itemImg = document.createElement('img');
        itemImg.src = baseItem.img || 'extension/default_item.png';
        itemImg.style.width = '100% !important';
        itemImg.style.height = '100% !important';
        itemImg.style.objectFit = 'contain !important';
        itemImg.style.position = 'absolute !important';
        itemImg.style.top = '0 !important';
        itemImg.style.left = '0 !important';
        itemImg.style.zIndex = '1 !important';
        itemImg.onerror = function() {
            this.src = 'extension/default_item.png';
        };
        slot.appendChild(itemImg);

        const count = document.createElement('span');
        count.className = 'clsk_bag_item_count';
        count.textContent = `${item.num}`;
        slot.appendChild(count);

        const name = document.createElement('span');
        name.className = 'clsk_bag_item_name';
        name.textContent = baseItem.name;
        name.style.color = rarityColors[rarity];
        slot.appendChild(name);
        // 装备状态标签
        if(item.isEquipped && item.equippedTo) {
            const equipStatus = document.createElement('span');
            equipStatus.className = 'clsk_bag_equip_status';
            equipStatus.textContent = `${item.equippedTo.charName}·${item.equippedTo.slotName}`;
            equipStatus.style.position = 'absolute';
            equipStatus.style.top = '2px';
            equipStatus.style.left = '2px';
            equipStatus.style.background = 'rgba(76, 175, 80, 0.9)';
            equipStatus.style.color = '#fff';
            equipStatus.style.fontSize = '10px';
            equipStatus.style.padding = '2px 4px';
            equipStatus.style.borderRadius = '2px';
            equipStatus.style.zIndex = '2';
            slot.appendChild(equipStatus);
        }

        slot.onmouseenter = function() {
            name.style.transform = 'translateY(0) !important';
        };
        slot.onmouseleave = function() {
            name.style.transform = 'translateY(100%) !important';
        };

        slot.onclick = function() {
            game.clskShowItemDetail(item);
        };

        grid.appendChild(slot);
    });

    // 补全空格子
    const totalNeed = lib.config.clsk_bag_max || 30;
    const emptyCount = totalNeed - itemList.length;
    for (let i = 0; i < emptyCount; i++) {
        const emptySlot = document.createElement('div');
        emptySlot.className = 'clsk_bag_item_slot empty';
        grid.appendChild(emptySlot);
    }
    game.clskUpdateBagTitle();
};

// 物品详情弹窗
game.clskShowItemDetail = function(item) {
    const baseItem = lib.clsk_bag[item.name];
    if (!baseItem) return;

    const typeMap = { consumables: '消耗品', material: '材料', equip: '装备', coin: '货币' };
    const rarityColors = {
        common: '#FFFFFF',    
        uncommon: '#4CAF50',  
        rare: '#1E90FF',
        epic: '#9370DB',
        legendary: '#FFD700', 
        mythic: '#FF4444',
    };
    const rarityText = {
        common: '普通',
        uncommon: '稀有',
        rare: '精良',
        epic: '史诗',
        legendary: '传说',
        mythic: '神话'
    };

    const bg = document.createElement('div');
    bg.style.position = 'fixed';
    bg.style.top = '0';
    bg.style.left = '0';
    bg.style.width = '100%';
    bg.style.height = '100%';
    bg.style.background = 'rgba(0, 0, 0, 0.8)';
    bg.style.zIndex = '99999';
    document.body.appendChild(bg);

    const box = document.createElement('div');
    box.style.position = 'fixed';
    box.style.top = '50%';
    box.style.left = '50%';
    box.style.transform = 'translate(-50%, -50%)';
    box.style.width = '450px';
    box.style.padding = '20px';
    box.style.background = '#222';
    box.style.border = `2px solid ${rarityColors[baseItem.rarity || 'common']}`;
    box.style.borderRadius = '8px';
    box.style.boxShadow = `0 0 20px ${rarityColors[baseItem.rarity || 'common']}40`;
    box.style.zIndex = '100000';
    box.style.fontFamily = 'sans-serif';
    box.style.color = '#fff';
    bg.appendChild(box);

    const itemImg = document.createElement('img');
    itemImg.src = baseItem.img || 'extension/default_item.png';
    itemImg.style.width = '80px';
    itemImg.style.height = '80px';
    itemImg.style.objectFit = 'contain';
    itemImg.style.display = 'block';
    itemImg.style.margin = '0 auto 15px auto';
    itemImg.style.borderRadius = '6px';
    itemImg.style.border = `1px solid ${rarityColors[baseItem.rarity || 'common']}`;
    itemImg.onerror = function() {
        this.src = 'extension/default_item.png';
    };
    box.appendChild(itemImg);

    const title = document.createElement('h3');
    title.textContent = baseItem.name; 
    title.style.margin = '0 0 15px 0';
    title.style.padding = '0';
    title.style.fontSize = '20px';
    title.style.color = rarityColors[baseItem.rarity || 'common'];
    title.style.textAlign = 'center';
    box.appendChild(title);

    const count = document.createElement('p');
    count.textContent = `数量：${item.num}`;
    count.style.margin = '0 0 10px 0';
    count.style.padding = '0';
    count.style.fontSize = '16px';
    box.appendChild(count);

    const type = document.createElement('p');
    type.textContent = `类型：${typeMap[item.type] || item.type}`;
    type.style.margin = '0 0 10px 0';
    type.style.padding = '0';
    type.style.fontSize = '16px';
    box.appendChild(type);

    if(baseItem.type === 'equip') {
        const slotText = baseItem.isTwoHanded ? '主手+副手（双手武器）' : CLSK_EQUIP_SLOTS[baseItem.equipSlot];
        const slot = document.createElement('p');
        slot.textContent = `装备部位：${slotText}`;
        slot.style.margin = '0 0 10px 0';
        slot.style.padding = '0';
        slot.style.fontSize = '16px';
        box.appendChild(slot);
    }

    const rarity = document.createElement('p');
    rarity.textContent = `品质：${rarityText[baseItem.rarity || 'common']}`;
    rarity.style.margin = '0 0 10px 0';
    rarity.style.padding = '0';
    rarity.style.fontSize = '16px';
    rarity.style.color = rarityColors[baseItem.rarity || 'common'];
    box.appendChild(rarity);

    if(item.isEquipped && item.equippedTo) {
        const equipInfo = document.createElement('p');
        equipInfo.textContent = `当前装备于：${item.equippedTo.charName} - ${item.equippedTo.slotName}`;
        equipInfo.style.margin = '0 0 10px 0';
        equipInfo.style.padding = '0';
        equipInfo.style.fontSize = '16px';
        equipInfo.style.color = '#4CAF50';
        box.appendChild(equipInfo);
    }

    const info = document.createElement('p');
    info.textContent = `简介：${item.info || baseItem.info}`;
    info.style.margin = '0 0 20px 0';
    info.style.padding = '0';
    info.style.fontSize = '16px';
    info.style.lineHeight = '1.5';
    box.appendChild(info);

    const btnWrapper = document.createElement('div');
    btnWrapper.style.display = 'flex';
    btnWrapper.style.justifyContent = 'center';
    btnWrapper.style.gap = '15px';
    box.appendChild(btnWrapper);

    const closeBtn = document.createElement('button');
    closeBtn.textContent = '关闭';
    closeBtn.style.padding = '8px 20px';
    closeBtn.style.fontSize = '16px';
    closeBtn.style.cursor = 'pointer';
    closeBtn.style.border = '1px solid #666';
    closeBtn.style.borderRadius = '4px';
    closeBtn.style.background = '#333';
    closeBtn.style.color = '#fff';
    closeBtn.onclick = () => document.body.removeChild(bg);
    btnWrapper.appendChild(closeBtn);

    if (baseItem.price && baseItem.price > 0) {
        const sellBtn = document.createElement('button');
        sellBtn.textContent = `出售 (${baseItem.price} 碎片/个)`;
        sellBtn.style.padding = '8px 20px';
        sellBtn.style.fontSize = '16px';
        sellBtn.style.cursor = 'pointer';
        sellBtn.style.border = '1px solid #FF9800';
        sellBtn.style.borderRadius = '4px';
        sellBtn.style.background = '#FF9800';
        sellBtn.style.color = '#fff';

        if (item.isEquipped) {
            sellBtn.disabled = true;
            sellBtn.style.opacity = '0.5';
            sellBtn.style.cursor = 'not-allowed';
            sellBtn.textContent = '已装备，无法出售';
        }

        sellBtn.onclick = () => {
            const totalGain = baseItem.price * item.num;
            const noConfirm = lib.config.clsk_sell_no_confirm;
            if (!noConfirm && !confirm(`确定要出售【${baseItem.name}】×${item.num}吗？\n出售后将获得 ${totalGain} 时空碎片`)) {
                return;
            }

            const loseSuccess = game.clskLoseItem2(item.id, item.num, true);
            if (!loseSuccess) return;

            game.clskGainItem('shikongsuipian', totalGain);
            document.body.removeChild(bg);
            game.clskRenderBagItems('all');
        };
        btnWrapper.appendChild(sellBtn);
    }

    if (baseItem.func) {
        if(item.isEquipped && item.equippedTo && baseItem.type === 'equip') {
            const unequipBtn = document.createElement('button');
            unequipBtn.textContent = '卸下装备';
            unequipBtn.style.padding = '8px 20px';
            unequipBtn.style.fontSize = '16px';
            unequipBtn.style.cursor = 'pointer';
            unequipBtn.style.border = '1px solid #FF9800';
            unequipBtn.style.borderRadius = '4px';
            unequipBtn.style.background = '#FF9800';
            unequipBtn.style.color = '#fff';
            unequipBtn.onclick = () => {
                game.clskUnequipFromCharacter(item);
                document.body.removeChild(bg);
            };
            btnWrapper.appendChild(unequipBtn);
        } 
        else if(baseItem.type === 'equip') {
            const equipBtn = document.createElement('button');
            equipBtn.textContent = '装备';
            equipBtn.style.padding = '8px 20px';
            equipBtn.style.fontSize = '16px';
            equipBtn.style.cursor = 'pointer';
            equipBtn.style.border = '1px solid #4CAF50';
            equipBtn.style.borderRadius = '4px';
            equipBtn.style.background = '#4CAF50';
            equipBtn.style.color = '#fff';
            equipBtn.onclick = () => {
                if (typeof baseItem.func === 'function') {
                    baseItem.func(item);
                }
                document.body.removeChild(bg);
            };
            btnWrapper.appendChild(equipBtn);
        }
        else {
            const useBtn = document.createElement('button');
            useBtn.textContent = '使用';
            useBtn.style.padding = '8px 20px';
            useBtn.style.fontSize = '16px';
            useBtn.style.cursor = 'pointer';
            useBtn.style.border = '1px solid #4CAF50';
            useBtn.style.borderRadius = '4px';
            useBtn.style.background = '#4CAF50';
            useBtn.style.color = '#fff';
            useBtn.onclick = () => {
                if (typeof baseItem.func === 'function') {
                    baseItem.func();
                }
                game.clskLoseItem2(item.id, 1);
                document.body.removeChild(bg);
            };
            btnWrapper.appendChild(useBtn);
        }
    }

    bg.onclick = (e) => e.target === bg && document.body.removeChild(bg);
};

// 7.武将装备检测核心工具方法

// 获取指定武将的全部装备
game.clskGetCharacterAllEquip = function(charId) {
  if (!charId) return [];
  const baseId = game.clskgetBaseCharId(charId);
  const equipObj = lib.clsk_character_equip[baseId] || {};
  return Object.values(equipObj)
    .filter(Boolean) 
    .map(equip => equip.equipName); 
};


// 获取指定武将指定栏位的装备
game.clskGetCharacterEquipBySlot = function(charId, slot) {
    if (!charId || !slot) return null;
    const baseId = game.clskgetBaseCharId(charId);
    const charEquip = lib.clsk_character_equip[baseId];
    if (!charEquip || !charEquip[slot]) return null;
    return JSON.parse(JSON.stringify(charEquip[slot]));
};

// 检测指定武将是否装备了某件物品
game.clskIsCharacterEquipItem = function(charId, itemName) {
    if (!charId || !itemName) return false;
    const baseId = game.clskgetBaseCharId(charId);
    const charEquip = lib.clsk_character_equip[baseId];
    if (!charEquip) return false;

    for (let slot in charEquip) {
        if (charEquip[slot].equipName === itemName) {
            return true;
        }
    }
    return false;
};

