// 卡池核心工具
const clsk_lucky_createBtn = function(text, className, parent, onclick) {
    const btn = document.createElement('div');
    btn.className = `clsk_lucky_btn ${className || ''}`;
    btn.innerHTML = text;
    btn.style.cssText = `
        display: inline-flex;
        align-items: center;
        justify-content: center;
        min-width: 100px;
        height: 40px;
        padding: 0 20px;
        border-radius: 6px;
        border: 2px solid #ffd700;
        background: rgba(50, 50, 50, 0.9);
        color: #fff;
        font-family: lishu;
        font-size: 16px;
        font-weight: bold;
        cursor: pointer;
        box-sizing: border-box;
        z-index: 10;
    `;
    const eventName = lib.config.touchscreen ? 'touchend' : 'click';
    if (typeof onclick === 'function') {
        btn.addEventListener(eventName, function(e) {
            e.stopPropagation();
            onclick();
        });
    }
    // 悬浮效果
    btn.addEventListener('mouseenter', function() {
        this.style.background = 'rgba(70, 70, 70, 0.95)';
    });
    btn.addEventListener('mouseleave', function() {
        this.style.background = 'rgba(50, 50, 50, 0.9)';
    });
    if (parent) parent.appendChild(btn);
    return btn;
};

// 品质
const CLSK_RARITY_COLORS = {
    common: 'clsk_rarity_common',
    uncommon: 'clsk_rarity_uncommon',
    rare: 'clsk_rarity_rare',
    epic: 'clsk_rarity_epic',
    legendary: 'clsk_rarity_legendary',
    mythic: 'clsk_rarity_mythic'
};

//开放时间检测
const clsk_isPoolOpen = function(poolConfig) {
    const now = new Date();
    // 固定时间段校验
    if (poolConfig.openTimeRange && Array.isArray(poolConfig.openTimeRange) && poolConfig.openTimeRange.length === 2) {
        const [startStr, endStr] = poolConfig.openTimeRange;
        const startTime = new Date(startStr.replace(/\./g, '-'));
        const endTime = new Date(endStr.replace(/\./g, '-'));
        if (isNaN(startTime.getTime()) || isNaN(endTime.getTime())) {
            return { isOpen: false, tip: '卡池时间配置格式错误！' };
        }
        if (now < startTime) {
            return { isOpen: false, tip: `该卡池将于${startStr}开放，敬请期待！` };
        }
        // 已结束开放
        if (now > endTime) {
            return { isOpen: false, tip: '该卡池已结束开放！' };
        }
    }
    // 每周开放日校验
    if (poolConfig.openWeekdays && Array.isArray(poolConfig.openWeekdays) && poolConfig.openWeekdays.length > 0) {
        const currentWeekday = now.getDay(); 
        if (!poolConfig.openWeekdays.includes(currentWeekday)) {
            const weekdayNameMap = ['日', '一', '二', '三', '四', '五', '六'];
            const openDaysText = poolConfig.openWeekdays.map(day => `周${weekdayNameMap[day]}`).join('、');
            return { isOpen: false, tip: `该卡池仅${openDaysText}开放！` };
        }
    }
    return { isOpen: true, tip: '卡池开放中' };
};

//卡池物品渲染
const clsk_renderItemSlot = function(itemId, count, showProbability, probability, isGuarantee = false) {
    const itemTemplate = lib.clsk_bag[itemId];
    if (!itemTemplate) return null;
    const wrap = document.createElement('div');
    wrap.className = 'clsk_item_wrap';
    wrap.style.cssText = `
        position: absolute;
        width: 80px;
        height: 130px;
    `;
    const slot = document.createElement('div');
    slot.className = `clsk_item_slot ${CLSK_RARITY_COLORS[itemTemplate.rarity || 'common']}`;
    slot.style.cssText = `
        width: 60px;
        height: 60px;
        margin: 0 auto;
        border-radius: 6px;
        background: #1a1a1a;
        display: flex;
        align-items: center;
        justify-content: center;
        position: relative;
        box-sizing: border-box;
    `;
    wrap.appendChild(slot);
    const img = document.createElement('img');
    img.src = itemTemplate.img || 'image/system/unknown.png';
    img.alt = itemTemplate.name;
    img.style.cssText = `
        width: 80%;
        height: 80%;
        object-fit: contain;
    `;
    img.onerror = function() { this.src = 'image/system/unknown.png'; };
    slot.appendChild(img);
    if (count > 1) {
        const countText = document.createElement('div');
        countText.className = 'clsk_item_count';
        countText.innerHTML = `×${count}`;
        countText.style.cssText = `
            position: absolute;
            right: 4px;
            bottom: 2px;
            font-size: 12px;
            color: #fff;
            text-shadow: 0 0 2px #000;
        `;
        slot.appendChild(countText);
    }
const text = document.createElement('div');
text.className = 'clsk_item_text';
text.style.cssText = `
    width: 100%;
    position: absolute;
    top: 70px; 
    left: 0;
    font-size: 12px;
    color: #fff;
    text-align: center;
    line-height: 1.2;
    word-break: break-all;
`;

    const namePrefix = isGuarantee ? '【大奖】' : '';
if (showProbability && probability) {
    text.innerHTML = `${namePrefix}${itemTemplate.name}<br/>${probability}%`;
} else {
    text.innerHTML = `${namePrefix}${itemTemplate.name}`;
}

    wrap.appendChild(text);

    return wrap;
};

//展示抽奖结果
const clsk_showDrawResult = function(resultList, callback) {
    document.querySelectorAll('.clsk_lucky_modal_bg').forEach(modal => modal.remove());

    // 合并抽奖结果
    const merged = {};
    resultList.forEach(item => {
        merged[item.itemId] = merged[item.itemId] 
            ? {...item, count: merged[item.itemId].count + item.count} 
            : {...item};
    });
    const finalList = Object.values(merged);
    const bg = document.createElement('div');
    bg.className = 'clsk_lucky_modal_bg';
    bg.style.cssText = `
        position: fixed !important;
        top: 0 !important;
        left: 0 !important;
        right: 0 !important;
        bottom: 0 !important;
        width: 100% !important;
        height: 100% !important;
        background: rgba(0, 0, 0, 0.9) !important;
        z-index: 1000002 !important;
    `;
    document.body.appendChild(bg);
    const box = document.createElement('div');
    box.className = 'clsk_lucky_modal_box';
    box.style.cssText = `
        position: absolute !important;
        left: 50% !important;
        top: 50% !important;
        transform: translate(-50%, -50%) !important;
        width: 90% !important;
        max-width: 700px !important;
        height: 80vh !important;
        max-height: 600px !important;
        background: #1a1a1a !important;
        border: 2px solid #ffd700 !important;
        border-radius: 8px !important;
        box-sizing: border-box !important;
    `;
    bg.appendChild(box);
    const title = document.createElement('div');
    title.className = 'clsk_lucky_modal_title';
    title.innerHTML = '恭喜你抽到了';
    title.style.cssText = `
        position: absolute !important;
        top: 20px !important;
        left: 0 !important;
        width: 100% !important;
        text-align: center !important;
        font-size: 24px !important;
        color: #ffd700 !important;
        z-index: 10 !important;
        margin: 0 !important;
        padding: 0 !important;
    `;
    box.appendChild(title);

    const content = document.createElement('div');
    content.className = 'clsk_lucky_modal_content';
    content.style.cssText = `
        position: absolute !important;
        top: 60px !important;
        bottom: 80px !important;
        left: 20px !important;
        right: 20px !important;
        overflow-y: auto !important;
        box-sizing: border-box !important;
        z-index: 5 !important;
    `;
    box.appendChild(content);

    const contentInner = document.createElement('div');
    contentInner.className = 'clsk_lucky_modal_content_inner';
    contentInner.style.cssText = `
        position: relative !important;
        width: 100% !important;
        box-sizing: border-box !important;
        padding-bottom: 20px;
    `;
    content.appendChild(contentInner);

    // 物品基础参数
    const itemWidth = 80;
    const itemHeight = 130;
    const gapX = 15;
    const gapY = 15;

    setTimeout(() => {
        const contentWidth = content.clientWidth;
        const colCount = Math.max(4, Math.floor(contentWidth / (itemWidth + gapX)));
        
        const totalRows = Math.ceil(finalList.length / colCount);
        const totalContentHeight = totalRows * (itemHeight + gapY);
        contentInner.style.height = `${totalContentHeight}px`;

        finalList.forEach((item, index) => {
            const col = index % colCount;
            const row = Math.floor(index / colCount);
            const itemLeft = col * (itemWidth + gapX);
            const itemTop = row * (itemHeight + gapY);

            const slot = clsk_renderItemSlot(item.itemId, item.count, false, undefined, item.isGuarantee);
            slot.style.left = `${itemLeft}px`;
            slot.style.top = `${itemTop}px`;
            contentInner.appendChild(slot);
        });
    }, 0);

    const btnGroup = document.createElement('div');
    btnGroup.className = 'clsk_lucky_modal_btnGroup';
    btnGroup.style.cssText = `
        position: absolute !important;
        bottom: 40px !important;
        left: 0 !important;
        width: 100% !important;
        text-align: center !important;
        z-index: 10 !important;
        margin: 0 !important;
        padding: 0 !important;
    `;
    box.appendChild(btnGroup);

    clsk_lucky_createBtn("确定", "", btnGroup, function() {
        bg.remove();
        if (typeof callback === 'function') callback();
    });

    bg.onclick = function(e) {
        if (e.target === bg) {
            bg.remove();
            if (typeof callback === 'function') callback();
        }
    };
};

// 奖池详情
const clsk_showPoolDetail = function(poolConfig) {
    document.querySelectorAll('.clsk_lucky_modal_bg').forEach(modal => modal.remove());
    
    const bg = document.createElement('div');
    bg.className = 'clsk_lucky_modal_bg';
    bg.style.cssText = `
        position: fixed !important;
        top: 0 !important;
        left: 0 !important;
        right: 0 !important;
        bottom: 0 !important;
        width: 100% !important;
        height: 100% !important;
        background: rgba(0, 0, 0, 0.95) !important;
        z-index: 1000002 !important;
    `;
    document.body.appendChild(bg);
    const box = document.createElement('div');
    box.className = 'clsk_lucky_modal_box';
    box.style.cssText = `
        position: absolute !important;
        left: 50% !important;
        top: 50% !important;
        transform: translate(-50%, -50%) !important;
        width: 90% !important;
        max-width: 800px !important;
        height: 85vh !important;
        max-height: 700px !important;
        background: #1a1a1a !important;
        border: 2px solid #ffd700 !important;
        border-radius: 8px !important;
        box-sizing: border-box !important;
    `;
    bg.appendChild(box);
    const title = document.createElement('div');
    title.className = 'clsk_lucky_modal_title';
    title.innerHTML = `${poolConfig.name} - 奖池详情`;
    title.style.cssText = `
        position: absolute !important;
        top: 20px !important;
        left: 0 !important;
        width: 100% !important;
        text-align: center !important;
        font-size: 24px !important;
        color: #ffd700 !important;
        z-index: 10 !important;
        margin: 0 !important;
        padding: 0 !important;
    `;
    box.appendChild(title);

    const content = document.createElement('div');
    content.className = 'clsk_lucky_modal_content';
    content.style.cssText = `
        position: absolute !important;
        top: 60px !important;
        bottom: 80px !important;
        left: 20px !important;
        right: 20px !important;
        overflow-y: auto !important;
        box-sizing: border-box !important;
        z-index: 5 !important;
    `;
    box.appendChild(content);

    const contentInner = document.createElement('div');
    contentInner.className = 'clsk_lucky_modal_content_inner';
    contentInner.style.cssText = `
        position: relative !important;
        width: 100% !important;
        box-sizing: border-box !important;
        padding-bottom: 20px; /* 给最底部留一点边距，避免文字贴底 */
    `;
    content.appendChild(contentInner);

    // 计算概率+排序
    const totalWeight = poolConfig.pool.reduce((sum, item) => sum + item.weight, 0);
    const sortedPool = [...poolConfig.pool].sort((a, b) => {
        const rarityA = lib.clsk_bag[a.itemId]?.rarity || 'common';
        const rarityB = lib.clsk_bag[b.itemId]?.rarity || 'common';
        const rarityOrder = ['mythic', 'legendary', 'epic', 'rare', 'uncommon', 'common'];
        return rarityOrder.indexOf(rarityA) - rarityOrder.indexOf(rarityB);
    });

    const itemWidth = 80;
    const itemHeight = 130;
    const gapX = 15;
    const gapY = 15;
    const colCount = 8;
    
    const totalRows = Math.ceil(sortedPool.length / colCount);
    const totalContentHeight = totalRows * (itemHeight + gapY);
    contentInner.style.height = `${totalContentHeight}px`;

    sortedPool.forEach((item, index) => {
        const col = index % colCount;
        const row = Math.floor(index / colCount);
        const itemLeft = col * (itemWidth + gapX);
        const itemTop = row * (itemHeight + gapY);

        const probability = ((item.weight / totalWeight) * 100).toFixed(2);
        const slot = clsk_renderItemSlot(item.itemId, item.count, true, probability, item.isGuarantee);
        slot.style.left = `${itemLeft}px`;
        slot.style.top = `${itemTop}px`;
        contentInner.appendChild(slot);
    });

    const btnGroup = document.createElement('div');
    btnGroup.className = 'clsk_lucky_modal_btnGroup';
    btnGroup.style.cssText = `
        position: absolute !important;
        bottom: 40px !important;
        left: 0 !important;
        width: 100% !important;
        text-align: center !important;
        z-index: 10 !important;
        margin: 0 !important;
        padding: 0 !important;
    `;
    box.appendChild(btnGroup);

    clsk_lucky_createBtn("关闭", "", btnGroup, function() {
        bg.remove();
    });

    bg.onclick = function(e) {
        if (e.target === bg) bg.remove();
    };
};

// 抽奖
game.clsk_lucky_doDraw = function(poolId, times) {
    const poolConfig = CLSK_LUCKY_FINAL_CONFIG.find(item => item.id === poolId);
    if (!poolConfig) {
        return false;
    }
    const poolOpenStatus = clsk_isPoolOpen(poolConfig);
    if (!poolOpenStatus.isOpen) {
        game.tis(poolOpenStatus.tip);
        return false;
    }
    const poolData = lib.config.clsk_lucky_final_data[poolId];
    const drawResults = [];

    const totalCost = poolConfig.cost.count * times;
    const hasEnough = game.clskGetItemUsableCount(poolConfig.cost.itemId) >= totalCost;
    if (!hasEnough) {
        const costItemName = lib.clsk_bag[poolConfig.cost.itemId]?.name || '消耗品';
        game.tis(`${costItemName}不足，无法进行抽奖！`);
        return false;
    }
    game.clskLoseItem(poolConfig.cost.itemId, totalCost, true);

    const totalWeight = poolConfig.pool.reduce((sum, item) => sum + item.weight, 0);
    const guaranteeList = poolConfig.pool.filter(item => item.isGuarantee);
    const hasGuarantee = poolConfig.guarantee && guaranteeList.length > 0;

    for (let i = 0; i < times; i++) {
        poolData.totalTimes++;
        poolData.guaranteeCount++;
        let selectedItem = null;

        // 保底
       if (hasGuarantee && poolData.guaranteeCount >= poolConfig.guarantee.times) {
    // 按权重随机抽取保底物品，没想到吧，你的保底也是一种抽奖
    const totalGuaranteeWeight = guaranteeList.reduce((sum, item) => sum + item.weight, 0);
    let randomNum = Math.random() * totalGuaranteeWeight;
    let currentWeight = 0;
    for (let item of guaranteeList) {
        currentWeight += item.weight;
        if (randomNum <= currentWeight) {
            selectedItem = item;
            break;
        }
    }
    poolData.guaranteeCount = 0;
          }else {
            // 普通抽奖
            let randomNum = Math.random() * totalWeight;
            let currentWeight = 0;
            for (let item of poolConfig.pool) {
                currentWeight += item.weight;
                if (randomNum <= currentWeight) {
                    selectedItem = item;
                    break;
                }
            }
            // 抽到保底物品，重置保底计数
            if (hasGuarantee && selectedItem.isGuarantee) {
                poolData.guaranteeCount = 0;
            }
        }

        if (selectedItem) {
            drawResults.push(selectedItem);
            game.clskGainItem(selectedItem.itemId, selectedItem.count);
        }
    }

    game.saveConfig('clsk_lucky_final_data', lib.config.clsk_lucky_final_data);
    if (game.clskRenderBagItems) {
        game.clskRenderBagItems(document.querySelector('.clsk_bag_tabButton.active')?.dataset.type || 'all');
    }

    return drawResults;
};

