// 商城核心工具
game.clskGetGoodsRemainLimit = function(goodsId) {
    const goods = CLSK_SHOP_CONFIG.goodsList.find(item => item.id === goodsId);
    if (!goods || goods.limitType === 'none') return Infinity;
    
    const limitRecord = lib.config.clsk_shop_limit[goodsId];
    const boughtCount = limitRecord ? limitRecord.count : 0;
    return Math.max(0, goods.limitCount - boughtCount);
};

game.clskCheckCurrencyEnough = function(priceList) {
    for (let price of priceList) {
        const haveCount = game.clskGetItemTotalCount(price.currency);
        if (haveCount < price.amount) return false;
    }
    return true;
};

//商城渲染方法
game.clskRenderShopItems = function(category) {
    const grid = document.getElementById('clsk_shop_grid');
    if (!grid) return;
    grid.innerHTML = '';

    let goodsList = CLSK_SHOP_CONFIG.goodsList.filter(item => 
        item.isOnSale && (category === 'all' || item.category === category)
    );

    goodsList.forEach(goods => {
        const remainLimit = game.clskGetGoodsRemainLimit(goods.id);
        const isSoldOut = remainLimit <= 0;
        const isCurrencyEnough = game.clskCheckCurrencyEnough(goods.price);

        const card = document.createElement('div');
        card.className = 'clsk_shop_goods_card';

        const icon = document.createElement('img');
        icon.className = 'clsk_shop_goods_icon';
        icon.src = goods.icon || 'extension/default_item.png';
        icon.onerror = function() { this.src = 'extension/default_item.png'; };
        card.appendChild(icon);

        const name = document.createElement('div');
        name.className = 'clsk_shop_goods_name';
        name.textContent = goods.name;
        card.appendChild(name);

        const priceBox = document.createElement('div');
        priceBox.className = 'clsk_shop_goods_price';
        goods.price.forEach(price => {
            const currencyItem = lib.clsk_bag[price.currency];
            const priceItem = document.createElement('span');
            priceItem.className = 'clsk_shop_price_item';
            priceItem.textContent = `${currencyItem?.name || price.currency}×${price.amount}`;
            priceBox.appendChild(priceItem);
        });
        card.appendChild(priceBox);

        if (goods.limitType !== 'none') {
            const limitTag = document.createElement('div');
            limitTag.className = `clsk_shop_limit_tag ${isSoldOut ? 'sold_out' : ''}`;
            const limitText = {
                'daily': '每日限购',
                'forever': '永久限购'
            };
            limitTag.textContent = isSoldOut 
                ? '已售罄' 
                : `${limitText[goods.limitType]}: ${remainLimit}/${goods.limitCount}`;
            card.appendChild(limitTag);
        }

        const buyBtn = document.createElement('button');
        buyBtn.className = 'clsk_shop_buy_btn';
        buyBtn.textContent = isSoldOut ? '已售罄' : '购买';
        buyBtn.disabled = isSoldOut || !isCurrencyEnough;
        buyBtn.onclick = function(e) {
            e.stopPropagation();
            game.clskBuyShopItem(goods.id);
        };
        card.appendChild(buyBtn);

        card.onclick = function() {
            game.clskShowShopGoodsDetail(goods);
        };

        grid.appendChild(card);
    });
};

// 购买商品
game.clskBuyShopItem = function(goodsId) {
    const goods = CLSK_SHOP_CONFIG.goodsList.find(item => item.id === goodsId);
    if (!goods) {
        game.tis('商品不存在，购买失败');
        return false;
    }

    const remainLimit = game.clskGetGoodsRemainLimit(goodsId);
    if (remainLimit <= 0) {
        game.tis('该商品已售罄，无法购买');
        return false;
    }

    if (!game.clskCheckCurrencyEnough(goods.price)) {
        game.tis('货币不足，购买失败');
        return false;
    }

    for (let price of goods.price) {
        const loseSuccess = game.clskLoseItem(price.currency, price.amount, true);
        if (!loseSuccess) {
            game.tis('货币扣除失败，购买已取消');
            return false;
        }
    }

    for (let itemName in goods.reward) {
        const gainCount = goods.reward[itemName];
        game.clskGainItem(itemName, gainCount, undefined, undefined, undefined, undefined, undefined, true);
    }

    if (goods.limitType !== 'none') {
        if (!lib.config.clsk_shop_limit[goodsId]) {
            lib.config.clsk_shop_limit[goodsId] = {
                type: goods.limitType,
                count: 0
            };
        }
        lib.config.clsk_shop_limit[goodsId].count += 1;
        game.saveConfig('clsk_shop_limit', lib.config.clsk_shop_limit);
    }

    game.tis(`成功购买【${goods.name}】！`);
    game.clskRenderShopItems(document.querySelector('.clsk_shop_tabButton.active')?.dataset.category || 'all');
    return true;
};

// 商品详情
game.clskShowShopGoodsDetail = function(goods) {
    const rarityColors = {
        common: '#FFFFFF',
        uncommon: '#4CAF50',
        rare: '#1E90FF',
        epic: '#9370DB',
        legendary: '#FFD700',
        mythic: '#FF4444'
    };
    const remainLimit = game.clskGetGoodsRemainLimit(goods.id);
    const isSoldOut = remainLimit <= 0;
    const isCurrencyEnough = game.clskCheckCurrencyEnough(goods.price);

    // 遮罩层
    const bg = document.createElement('div');
    bg.style.position = 'fixed';
    bg.style.top = '0';
    bg.style.left = '0';
    bg.style.width = '100%';
    bg.style.height = '100%';
    bg.style.background = 'rgba(0, 0, 0, 0.85)';
    bg.style.zIndex = '2050';
    bg.style.display = 'flex';
    bg.style.alignItems = 'center';
    bg.style.justifyContent = 'center';
    bg.style.boxSizing = 'border-box';
    document.body.appendChild(bg);

    // 弹窗主体
    const box = document.createElement('div');
    box.style.width = '450px';
    box.style.maxWidth = '90%';
    box.style.height = '600px';
    box.style.maxHeight = '80vh';
    box.style.background = '#1a1a1a';
    box.style.border = '2px solid #ffd700';
    box.style.borderRadius = '8px';
    box.style.boxShadow = '0 0 20px rgba(255,215,0,0.5)';
    box.style.boxSizing = 'border-box';
    box.style.position = 'relative';
    bg.appendChild(box);

    // 内容滚动
    const contentBox = document.createElement('div');
    contentBox.style.position = 'absolute';
    contentBox.style.top = '0';
    contentBox.style.left = '0';
    contentBox.style.width = '100%';
    contentBox.style.height = 'calc(100% - 80px)';
    contentBox.style.overflowY = 'auto';
    contentBox.style.padding = '25px';
    contentBox.style.boxSizing = 'border-box';
    box.appendChild(contentBox);

    // 商品图标
    const icon = document.createElement('img');
    icon.src = goods.icon || 'extension/default_item.png';
    icon.style.width = '100px';
    icon.style.height = '100px';
    icon.style.objectFit = 'contain';
    icon.style.display = 'block';
    icon.style.margin = '0 auto 20px auto';
    icon.style.borderRadius = '8px';
    icon.style.border = '2px solid #ffd700';
    icon.onerror = function() { this.src = 'extension/default_item.png'; };
    contentBox.appendChild(icon);

    // 商品名称
    const title = document.createElement('h3');
    title.textContent = goods.name;
    title.style.margin = '0 0 25px 0';
    title.style.fontSize = '22px';
    title.style.color = '#ffd700';
    title.style.textAlign = 'center';
    title.style.fontFamily = 'lishu';
    title.style.lineHeight = '1.4';
    title.style.wordBreak = 'break-word';
    contentBox.appendChild(title);

    // 购买所需标题
    const priceTitle = document.createElement('p');
    priceTitle.textContent = '购买所需：';
    priceTitle.style.margin = '0 0 12px 0';
    priceTitle.style.fontSize = '16px';
    priceTitle.style.color = '#fff';
    priceTitle.style.fontFamily = 'lishu';
    contentBox.appendChild(priceTitle);

    // 价格列表
    goods.price.forEach(price => {
        const currencyItem = lib.clsk_bag[price.currency];
        const haveCount = game.clskGetItemTotalCount(price.currency);
        const priceItem = document.createElement('p');
        priceItem.style.margin = '0 0 8px 10px';
        priceItem.style.fontSize = '15px';
        priceItem.style.color = haveCount >= price.amount ? '#ffd700' : '#ff4444';
        priceItem.style.fontFamily = 'lishu';
        priceItem.style.lineHeight = '22px';
        priceItem.style.wordBreak = 'break-word';
        priceItem.textContent = `${currencyItem?.name || price.currency} × ${price.amount} (持有: ${haveCount})`;
        contentBox.appendChild(priceItem);
    });

    // 限购规则
    if (goods.limitType !== 'none') {
        const limitText = { daily: '每日限购', forever: '永久限购' };
        const limitInfo = document.createElement('p');
        limitInfo.textContent = `限购规则：${limitText[goods.limitType]} ${goods.limitCount}次，剩余可购买 ${remainLimit} 次`;
        limitInfo.style.margin = '20px 0 0 0';
        limitInfo.style.fontSize = '16px';
        limitInfo.style.color = isSoldOut ? '#ff4444' : '#4CAF50';
        limitInfo.style.fontFamily = 'lishu';
        limitInfo.style.lineHeight = '1.5';
        contentBox.appendChild(limitInfo);
    }

    // 购买获得标题
    const rewardTitle = document.createElement('p');
    rewardTitle.textContent = '购买获得：';
    rewardTitle.style.margin = '25px 0 12px 0';
    rewardTitle.style.fontSize = '16px';
    rewardTitle.style.color = '#fff';
    rewardTitle.style.fontFamily = 'lishu';
    contentBox.appendChild(rewardTitle);

    // 奖励列表
    for (let itemName in goods.reward) {
        const itemTemplate = lib.clsk_bag[itemName];
        const rewardItem = document.createElement('p');
        rewardItem.style.margin = '0 0 8px 10px';
        rewardItem.style.fontSize = '15px';
        rewardItem.style.color = rarityColors[itemTemplate?.rarity || 'common'];
        rewardItem.style.fontFamily = 'lishu';
        rewardItem.style.lineHeight = '22px';
        rewardItem.style.wordBreak = 'break-word';
        rewardItem.textContent = `${itemTemplate?.name || itemName} × ${goods.reward[itemName]}`;
        contentBox.appendChild(rewardItem);
    }

    // 底部按钮区
    const btnBox = document.createElement('div');
    btnBox.style.position = 'absolute';
    btnBox.style.bottom = '0';
    btnBox.style.left = '0';
    btnBox.style.width = '100%';
    btnBox.style.height = '80px';
    btnBox.style.borderTop = '1px solid #333';
    btnBox.style.display = 'flex';
    btnBox.style.alignItems = 'center';
    btnBox.style.justifyContent = 'center';
    btnBox.style.gap = '20px';
    btnBox.style.boxSizing = 'border-box';
    btnBox.style.background = '#1a1a1a';
    box.appendChild(btnBox);

    // 关闭按钮
    const closeBtn = document.createElement('button');
    closeBtn.className = 'clsk_lucky_btn';
    closeBtn.textContent = '关闭';
    closeBtn.onclick = () => document.body.removeChild(bg);
    btnBox.appendChild(closeBtn);

    // 购买按钮
    const buyBtn = document.createElement('button');
    buyBtn.className = 'clsk_lucky_btn';
    buyBtn.textContent = isSoldOut ? '已售罄' : '立即购买';
    buyBtn.style.background = isSoldOut ? '#666' : '#4CAF50';
    buyBtn.style.borderColor = isSoldOut ? '#666' : '#4CAF50';
    buyBtn.disabled = isSoldOut || !isCurrencyEnough;
    buyBtn.onclick = () => {
        const success = game.clskBuyShopItem(goods.id);
        if (success) document.body.removeChild(bg);
    };
    btnBox.appendChild(buyBtn);

    // 点击遮罩关闭
    bg.onclick = (e) => e.target === bg && document.body.removeChild(bg);
};

// 打开商城
game.clskOpenShop = function() {
    let shopPage = document.getElementById('clsk_shop_page');
    if (shopPage) {
        shopPage.classList.add('active');
        game.clskRenderShopItems('all');
        return;
    }

    shopPage = document.createElement('div');
    shopPage.id = 'clsk_shop_page';
    document.body.appendChild(shopPage);

    const mainContainer = document.createElement('div');
    mainContainer.id = 'clsk_shop_mainContainer';
    shopPage.appendChild(mainContainer);

    const title = document.createElement('div');
    title.id = 'clsk_shop_title';
    title.textContent = '错乱时空 - 商城';
    mainContainer.appendChild(title);

    const closeBtn = document.createElement('div');
    closeBtn.id = 'clsk_shop_closeButton';
    closeBtn.textContent = '×';
    closeBtn.onclick = game.clskCloseShop;
    mainContainer.appendChild(closeBtn);

    const tabContainer = document.createElement('div');
    tabContainer.id = 'clsk_shop_tabContainer';
    mainContainer.appendChild(tabContainer);

    const gridContainer = document.createElement('div');
    gridContainer.id = 'clsk_shop_gridContainer';
    mainContainer.appendChild(gridContainer);

    const grid = document.createElement('div');
    grid.id = 'clsk_shop_grid';
    gridContainer.appendChild(grid);

    const categoryList = [
        { key: 'all', name: '全部商品' },
        ...Object.entries(CLSK_SHOP_CONFIG.category).map(([key, name]) => ({ key, name }))
    ];
    categoryList.forEach(item => {
        const tabBtn = document.createElement('div');
        tabBtn.className = 'clsk_bag_tabButton';
        tabBtn.textContent = item.name;
        tabBtn.dataset.category = item.key;
        if (item.key === 'all') tabBtn.classList.add('active');
        tabBtn.onclick = function() {
            document.querySelectorAll('#clsk_shop_tabContainer .clsk_bag_tabButton').forEach(btn => btn.classList.remove('active'));
            this.classList.add('active');
            game.clskRenderShopItems(this.dataset.category);
        };
        tabContainer.appendChild(tabBtn);
    });

    shopPage.onclick = function(e) {
        if (e.target === shopPage) game.clskCloseShop();
    };

    game.clskRenderShopItems('all');
    shopPage.classList.add('active');
};

//关闭商城
game.clskCloseShop = function() {
    const shopPage = document.getElementById('clsk_shop_page');
    if (shopPage) shopPage.classList.remove('active');
};

