// 任务系统初始化
if (lib.config.clsk_task_data === undefined) {
  game.saveConfig('clsk_task_data', {
    lastDailyReset: new Date().setHours(0, 0, 0, 0),
    lastWeeklyReset: (() => {
      const now = new Date();
      const dayOfWeek = now.getDay();
      const mondayOffset = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
      return new Date(now.setDate(now.getDate() - mondayOffset)).setHours(0, 0, 0, 0);
    })(),
    dailyTasks: CLSK_TASK_TEMPLATE.daily.map(task => ({
      taskId: task.taskId,
      current: 0,
      isClaimed: false
    })),
    weeklyTasks: CLSK_TASK_TEMPLATE.weekly.map(task => ({
      taskId: task.taskId,
      current: 0,
      isClaimed: false
    })),
    limitTasks: CLSK_TASK_TEMPLATE.limit.map(task => ({
      taskId: task.taskId,
      current: 0,
      isClaimed: false
    })),
    achievementTasks: CLSK_TASK_TEMPLATE.achievement.map(task => ({
      taskId: task.taskId,
      current: 0,
      isClaimed: false
    }))
  });
}
lib.clsk_task_data = JSON.parse(JSON.stringify(lib.config.clsk_task_data));

game.clskResetSingleTask = function(taskId) {
  if (!taskId) return false;

  const taskData = lib.clsk_task_data;
  const taskTypes = ['daily', 'weekly', 'limit', 'achievement'];
  let task = null;
  let taskType = '';
  
  for (const type of taskTypes) {
    const findTask = taskData[`${type}Tasks`]?.find(item => item.taskId === taskId);
    if (findTask) {
      task = findTask;
      taskType = type;
      break;
    }
  }

  const taskTemplate = CLSK_TASK_TEMPLATE[taskType]?.find(t => t.taskId === taskId);
  if (!task || !taskTemplate) return false;

  task.current = 0;
  task.isClaimed = false;
  lib.config.clsk_task_data = JSON.parse(JSON.stringify(taskData));
  game.saveConfig('clsk_task_data', lib.config.clsk_task_data);
  const activeTab = document.querySelector('.clsk_task_tabButton.active')?.dataset.type;
  if (activeTab) game.clskRenderTaskList(activeTab);
  return true;
};

/*
  total: 每日任务总数
  achieved: 已达成目标的任务数
  claimed: 已领取奖励的任务数
  isAllAchieved: 是否全部任务都达成了目标
  isAllClaimed: 是否全部任务都领取了奖励
 */
game.getDailyTaskStatus = function() {
  const taskData = lib.clsk_task_data;
  const dailyTasks = taskData.dailyTasks || [];
  const templateList = CLSK_TASK_TEMPLATE.daily || [];
  const total = dailyTasks.length;
  
  let achieved = 0;
  let claimed = 0;

  dailyTasks.forEach(task => {
    const template = templateList.find(t => t.taskId === task.taskId);
    if (!template) return;
    if (task.current >= template.target) achieved++;
    if (task.isClaimed) claimed++;
  });

  return {
    total,
    achieved,
    claimed,
    isAllAchieved: achieved === total && total > 0,
    isAllClaimed: claimed === total && total > 0
  };
};

//每周任务检测
game.getWeeklyTaskStatus = function() {
  const taskData = lib.clsk_task_data;
  const weeklyTasks = taskData.weeklyTasks || [];
  const templateList = CLSK_TASK_TEMPLATE.weekly || [];
  const total = weeklyTasks.length;
  
  let achieved = 0;
  let claimed = 0;

  weeklyTasks.forEach(task => {
    const template = templateList.find(t => t.taskId === task.taskId);
    if (!template) return;
    if (task.current >= template.target) achieved++;
    if (task.isClaimed) claimed++;
  });

  return {
    total,
    achieved,
    claimed,
    isAllAchieved: achieved === total && total > 0,
    isAllClaimed: claimed === total && total > 0
  };
};

/*
  检测成就任务完成状态
  total: 成就总数
  achieved: 已达成目标的成就数
  claimed: 已领取奖励的成就数
 unClaimed: 达成了但没领奖励的成就数
 unAchieved: 还没达成的成就数
 */
game.getAchievementStatus = function() {
  const taskData = lib.clsk_task_data;
  const achievementTasks = taskData.achievementTasks || [];
  const templateList = CLSK_TASK_TEMPLATE.achievement || [];
  const total = achievementTasks.length;
  
  let achieved = 0;
  let claimed = 0;

  achievementTasks.forEach(task => {
    const template = templateList.find(t => t.taskId === task.taskId);
    if (!template) return;
    if (task.current >= template.target) achieved++;
    if (task.isClaimed) claimed++;
  });

  return {
    total,
    achieved,
    claimed,
    unClaimed: achieved - claimed,
    unAchieved: total - achieved
  };
};

// 一次性获取所有任务的统计数据
game.getAllTaskStatus = function() {
  return {
    daily: game.getDailyTaskStatus(),
    weekly: game.getWeeklyTaskStatus(),
    achievement: game.getAchievementStatus()
  };
};

//检测任务重置
game.clskCheckTaskReset = function() {
  const now = new Date();
  const nowTime = now.getTime();
  const todayZero = now.setHours(0, 0, 0, 0);
  const taskData = lib.clsk_task_data;
  let isReset = false;
  let isTaskUpdated = false;

  if (taskData.lastDailyReset < todayZero) {
    taskData.dailyTasks = CLSK_TASK_TEMPLATE.daily.map(task => ({
      taskId: task.taskId,
      current: 0,
      isClaimed: false
    }));
    taskData.lastDailyReset = todayZero;
    isReset = true;
  }

  const dayOfWeek = now.getDay();
  const mondayOffset = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
  const thisMondayZero = new Date(now.setDate(now.getDate() - mondayOffset)).setHours(0, 0, 0, 0);
  if (taskData.lastWeeklyReset < thisMondayZero) {
    taskData.weeklyTasks = CLSK_TASK_TEMPLATE.weekly.map(task => ({
      taskId: task.taskId,
      current: 0,
      isClaimed: false
    }));
    taskData.lastWeeklyReset = thisMondayZero;
    isReset = true;
  }

  const taskTypes = ['daily', 'weekly', 'limit', 'achievement'];
  taskTypes.forEach(type => {
    const templateList = CLSK_TASK_TEMPLATE[type];
    const saveKey = `${type}Tasks`;
    if (!taskData[saveKey]) {
      taskData[saveKey] = templateList.map(task => ({
        taskId: task.taskId,
        current: 0,
        isClaimed: false
      }));
      isTaskUpdated = true;
      return;
    }

    templateList.forEach(templateTask => {
      const hasTask = taskData[saveKey].some(task => task.taskId === templateTask.taskId);
      if (!hasTask) {
        taskData[saveKey].push({
          taskId: templateTask.taskId,
          current: 0,
          isClaimed: false
        });
        isTaskUpdated = true;
      }
    });

    const validTaskIds = templateList.map(t => t.taskId);

    const originalLength = taskData[saveKey].length;
    taskData[saveKey] = taskData[saveKey].filter(task => validTaskIds.includes(task.taskId));
    if (taskData[saveKey].length !== originalLength) {
      isTaskUpdated = true;
    }
  });

  if (isReset || isTaskUpdated) {
    lib.config.clsk_task_data = JSON.parse(JSON.stringify(taskData));
    game.saveConfig('clsk_task_data', lib.config.clsk_task_data);
    lib.clsk_task_data = JSON.parse(JSON.stringify(lib.config.clsk_task_data));
  }
};

//增长任务进度
game.clskUpdateTaskProgress = function(taskId, addNum = 1) {
  if(lib.config.extension_错乱时空_cl_youkemoshi)return false;
  if (!taskId || addNum <= 0) return false;

  const taskData = lib.clsk_task_data;
  const taskTypes = ['daily', 'weekly', 'limit', 'achievement'];
  let task = null;
  let taskTemplate = null;
  
  for (const type of taskTypes) {
    const findTask = taskData[`${type}Tasks`]?.find(item => item.taskId === taskId);
    if (findTask) {
      task = findTask;
      taskTemplate = CLSK_TASK_TEMPLATE[type]?.find(t => t.taskId === taskId);
      break;
    }
  }

  if (taskTemplate?.startTime && taskTemplate?.endTime) {
    const nowTime = new Date().getTime();
    if (nowTime < taskTemplate.startTime || nowTime > taskTemplate.endTime) {
      return false;
    }
  }

  if (!task || !taskTemplate || task.isClaimed || task.current >= taskTemplate.target) {
    return false;
  }

  task.current = Math.min(task.current + addNum, taskTemplate.target);
  lib.config.clsk_task_data = JSON.parse(JSON.stringify(taskData));
  game.saveConfig('clsk_task_data', lib.config.clsk_task_data);

  const activeTab = document.querySelector('.clsk_task_tabButton.active')?.dataset.type;
  if (activeTab) game.clskRenderTaskList(activeTab);
  return true;
};

// 检测任务进度
game.clskGetOnlyTaskProgress = function(taskId) {
  if (!taskId) return 0;
  const taskTypes = ['daily', 'weekly', 'limit', 'achievement'];
  for (const type of taskTypes) {
    const task = lib.clsk_task_data[`${type}Tasks`]?.find(item => item.taskId === taskId);
    if (task) return task.current;
  }
  return 0;
};

//领取任务奖励
game.clskClaimTaskReward = function(taskId) {
  if (!taskId) return false;

  const taskData = lib.clsk_task_data;
  const taskTypes = ['daily', 'weekly', 'limit', 'achievement'];
  let task = null;
  let taskType = '';
  
  for (const type of taskTypes) {
    const findTask = taskData[`${type}Tasks`]?.find(item => item.taskId === taskId);
    if (findTask) {
      task = findTask;
      taskType = type;
      break;
    }
  }
  const taskTemplate = CLSK_TASK_TEMPLATE[taskType]?.find(t => t.taskId === taskId);

  // 限时任务校验
  if (taskTemplate?.startTime && taskTemplate?.endTime) {
    const nowTime = new Date().getTime();
    if (nowTime > taskTemplate.endTime) {
      game.tis('活动已结束，无法领取奖励！');
      return false;
    }
  }

  if (!task || !taskTemplate || task.current < taskTemplate.target || task.isClaimed) {
    return false;
  }
  taskTemplate.rewards.forEach(reward => {
    game.clskGainItem(reward.itemName, reward.num);
  });

  task.isClaimed = true;
  lib.config.clsk_task_data = JSON.parse(JSON.stringify(taskData));
  game.saveConfig('clsk_task_data', lib.config.clsk_task_data);

  game.clskRenderTaskList(taskType);
  game.tis(`成功领取【${taskTemplate.name}】的奖励！`);
  var jc = game.getDailyTaskStatus();
  if(jc.isAllAchieved&&game.clskGetOnlyTaskProgress("achievement_complete_daily_10")<10)game.clskUpdateTaskProgress("achievement_complete_daily_10")
  return true;
};

