//任务列表渲染
game.clskRenderTaskList = function(type) {
  const contentBox = document.getElementById('clsk_task_content');
  if (!contentBox) return;
  contentBox.innerHTML = '';

  const formatTime = {
    remain: (endTime) => {
      const now = new Date().getTime();
      const remain = endTime - now;
      if (remain <= 0) return '已过期';
      const day = Math.floor(remain / (1000 * 60 * 60 * 24));
      const hour = Math.floor((remain % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
      const min = Math.floor((remain % (1000 * 60 * 60)) / (1000 * 60));
      if (day > 0) return `剩余${day}天${hour}h`;
      if (hour > 0) return `剩余${hour}h${min}m`;
      return `剩余${min}m`;
    },
    waitStart: (startTime) => {
      const now = new Date().getTime();
      const wait = startTime - now;
      if (wait <= 0) return '即将开启';
      const day = Math.floor(wait / (1000 * 60 * 60 * 24));
      const hour = Math.floor((wait % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
      if (day > 0) return `${day}天后开`;
      if (hour > 0) return `${hour}h后开`;
      return '即将开启';
    }
  };

  const contentWidth = contentBox.clientWidth;
  const paddingX = 25; 
  let paddingY = 20; 
  const taskItemWidth = contentWidth - paddingX * 2; 
  const taskItemHeight = 110; 
  const rowGap = 18; 
  const itemsPerRow = 1; 
  const nowTime = new Date().getTime();

  const taskList = lib.clsk_task_data[`${type}Tasks`];
  const templateList = CLSK_TASK_TEMPLATE[type];
  if (!taskList || !templateList) return;

  let filterTaskList = [];
  let topTip = '';
  switch(type) {
    case 'limit':
      filterTaskList = taskList.filter(task => {
        const template = templateList.find(t => t.taskId === task.taskId);
        if (!template) return false;
        return nowTime <= template.endTime; 
      });
      topTip = '限时任务，有时间限制的！';
      break;
    case 'achievement':
      filterTaskList = taskList;
      topTip = '完成成就可以获得大量奖励！';
      break;
    default:
      filterTaskList = taskList;
      break;
  }

  if (topTip) {
    const tipBox = document.createElement('div');
    tipBox.style.position = 'relative';
    tipBox.style.width = '100%';
    tipBox.style.height = '40px';
    tipBox.style.lineHeight = '40px';
    tipBox.style.textAlign = 'center';
    tipBox.style.fontSize = '14px';
    tipBox.style.color = type === 'limit' ? '#ff4444' : '#4CAF50';
    tipBox.style.fontWeight = 'bold';
    tipBox.textContent = topTip;
    contentBox.appendChild(tipBox);
    paddingY = 10;
  }

  const totalRow = Math.ceil(filterTaskList.length / itemsPerRow);
  const totalContentHeight = paddingY * 2 + totalRow * (taskItemHeight + rowGap) - rowGap;

  const scrollInner = document.createElement('div');
  scrollInner.style.position = 'relative';
  scrollInner.style.width = '100%';
  scrollInner.style.height = totalContentHeight + 'px';
  scrollInner.style.margin = '0';
  scrollInner.style.padding = '0';
  contentBox.appendChild(scrollInner);

  filterTaskList.forEach((task, index) => {
    const template = templateList.find(t => t.taskId === task.taskId);
    if (!template) return;

    const row = Math.floor(index / itemsPerRow);
    const col = index % itemsPerRow;

    const left = paddingX + col * (taskItemWidth + rowGap);
    const top = paddingY + row * (taskItemHeight + rowGap);

    const taskItem = document.createElement('div');
    taskItem.style.position = 'absolute';
    taskItem.style.left = left + 'px';
    taskItem.style.top = top + 'px';
    taskItem.style.width = taskItemWidth + 'px';
    taskItem.style.height = taskItemHeight + 'px';
    taskItem.style.padding = '0';
    taskItem.style.background = 'rgba(50, 50, 50, 0.9)';
    taskItem.style.border = '2px solid #666';
    if (type === 'achievement' && task.isClaimed) {
      taskItem.style.border = '2px solid #ffd700';
      taskItem.style.background = 'rgba(80, 60, 20, 0.9)';
    }
    taskItem.style.borderRadius = '8px';
    taskItem.style.boxSizing = 'border-box';
    taskItem.style.overflow = 'hidden';
    scrollInner.appendChild(taskItem);

    let taskStatus = 'normal';
    let timeText = '';
    if (type === 'limit') {
      if (nowTime < template.startTime) {
        taskStatus = 'wait';
        timeText = formatTime.waitStart(template.startTime);
      } else {
        taskStatus = 'running';
        timeText = formatTime.remain(template.endTime);
      }
    }

    const isFinished = task.current >= template.target;
    const isClaimed = task.isClaimed;
    const taskName = document.createElement('h4');
    taskName.style.position = 'absolute';
    taskName.style.top = '12px';
    taskName.style.left = '18px';
    taskName.style.width = 'calc(100% - 36px)';
    taskName.style.height = '26px';
    taskName.style.lineHeight = '26px';
    taskName.style.margin = '0';
    taskName.style.padding = '0';
    taskName.style.fontFamily = 'lishu';
    taskName.style.fontSize = '20px';
    taskName.style.color = '#ffd700';
    taskName.style.overflow = 'hidden';
    taskName.style.textOverflow = 'ellipsis';
    taskName.style.whiteSpace = 'nowrap';
    taskName.textContent = template.name;
    taskItem.appendChild(taskName);

    const taskDesc = document.createElement('p');
    taskDesc.style.position = 'absolute';
    taskDesc.style.top = '42px';
    taskDesc.style.left = '18px';
    taskDesc.style.width = type === 'limit' ? 'calc(100% - 300px)' : 'calc(100% - 320px)';
    taskDesc.style.height = '22px';
    taskDesc.style.lineHeight = '22px';
    taskDesc.style.margin = '0';
    taskDesc.style.padding = '0';
    taskDesc.style.fontSize = '15px';
    taskDesc.style.color = '#ddd';
    taskDesc.style.overflow = 'hidden';
    taskDesc.style.textOverflow = 'ellipsis';
    taskDesc.style.whiteSpace = 'nowrap';
    taskDesc.textContent = template.desc;
    taskItem.appendChild(taskDesc);

    const progressText = document.createElement('p');
    progressText.style.position = 'absolute';
    progressText.style.top = '68px';
    progressText.style.left = '18px';
    progressText.style.width = type === 'limit' ? 'calc(100% - 300px)' : 'calc(100% - 320px)';
    progressText.style.height = '22px';
    progressText.style.lineHeight = '22px';
    progressText.style.margin = '0';
    progressText.style.padding = '0';
    progressText.style.fontSize = '15px';
    progressText.style.fontWeight = 'bold';
    progressText.style.color = isFinished ? '#4CAF50' : '#fff';
    progressText.textContent = `进度：${task.current}/${template.target}`;
    taskItem.appendChild(progressText);

    const rewardText = document.createElement('p');
    rewardText.style.position = 'absolute';
    rewardText.style.top = '12px';
    rewardText.style.right = '18px';
    rewardText.style.width = '280px';
    rewardText.style.height = '22px';
    rewardText.style.lineHeight = '22px';
    rewardText.style.margin = '0';
    rewardText.style.padding = '0';
    rewardText.style.fontSize = '13px';
    rewardText.style.color = '#ffd700';
    rewardText.style.textAlign = 'right';
    rewardText.style.overflow = 'hidden';
    rewardText.style.textOverflow = 'ellipsis';
    rewardText.style.whiteSpace = 'nowrap';
    rewardText.textContent = `奖励：${template.rewards.map(r => `${lib.clsk_bag[r.itemName]?.name || r.itemName}×${r.num}`).join('、')}`;
    taskItem.appendChild(rewardText);

    if (type === 'limit') {
      const timeTip = document.createElement('p');
      timeTip.style.position = 'absolute';
      timeTip.style.top = '36px'; 
      timeTip.style.right = '18px';
      timeTip.style.width = '100px'; 
      timeTip.style.height = '22px';
      timeTip.style.lineHeight = '22px';
      timeTip.style.margin = '0';
      timeTip.style.padding = '0';
      timeTip.style.fontSize = '14px';
      timeTip.style.fontWeight = 'bold';
      timeTip.style.textAlign = 'right';
      timeTip.style.overflow = 'hidden';
      timeTip.style.whiteSpace = 'nowrap';
      timeTip.style.color = taskStatus === 'running' ? '#ff4444' : '#ffaa00';
      timeTip.textContent = timeText;
      taskItem.appendChild(timeTip);
    }
    
    const actionBtn = document.createElement('button');
    actionBtn.className = 'clsk_lucky_btn';
    actionBtn.style.position = 'absolute';
    actionBtn.style.bottom = '12px';
    actionBtn.style.right = '18px';
    actionBtn.style.width = '140px';
    actionBtn.style.height = '40px';
    actionBtn.style.lineHeight = '40px';
    actionBtn.style.padding = '0';
    actionBtn.style.margin = '0';
    actionBtn.style.boxSizing = 'border-box';
    actionBtn.style.fontSize = '16px';

    if (type === 'limit' && taskStatus === 'wait') {
      actionBtn.textContent = '即将开启';
      actionBtn.disabled = true;
      actionBtn.style.opacity = '0.5';
      actionBtn.style.cursor = 'not-allowed';
    } else if (isClaimed) {
      actionBtn.textContent = type === 'achievement' ? '已达成' : '已领取';
      actionBtn.disabled = true;
      actionBtn.style.opacity = '0.5';
      actionBtn.style.cursor = 'not-allowed';
    } else if (isFinished) {
      actionBtn.textContent = '领取奖励';
      actionBtn.style.background = '#4CAF50';
      actionBtn.style.borderColor = '#4CAF50';
      actionBtn.onclick = () => game.clskClaimTaskReward(task.taskId);
    } else {
      actionBtn.textContent = '未完成';
      actionBtn.disabled = true;
      actionBtn.style.opacity = '0.5';
      actionBtn.style.cursor = 'not-allowed';
    }
    taskItem.appendChild(actionBtn);
  });
};

