//无敌的源神战胜了鸽府包
window.CLSK_Emotion = {
    cache: {},
    initialized: false,
    chatEnhanced: false,
    currentDetailPanel: null // 专门记当前打开的详情面板
};

get.is.emotion = function (str) {
    return true;
}

function clsk_addEmotionPack(packId, showName, count, imgPath) {
    var fixedPath = imgPath.replace(/\/$/, "") + "/";
    CLSK_Emotion.cache[packId] = {
        id: packId,
        name: showName,
        count: count,
        path: fixedPath,
        files: Array.from({ length: count }, function (_, i) {
            return (i + 1) + ".gif";
        })
    };
}

function loadClskEmotions() {
    clsk_addEmotionPack(
        "clsk_cuoluan",
        "错乱时空",
        15,
        "extension/错乱时空/emo/clsk"
    );
}

function CLSK_Emotion_TitleClick(uiintro, packList) {
    if (CLSK_Emotion.currentDetailPanel) {
        CLSK_Emotion.currentDetailPanel.remove();
        CLSK_Emotion.currentDetailPanel = null;
    }
    if (packList) packList.style.display = '';
    if (uiintro) uiintro._clsk_emotion_injected = false;
}

function enhanceChatUI() {
    if (CLSK_Emotion.chatEnhanced) return;
    CLSK_Emotion.chatEnhanced = true;
    var originalChat = ui.click.chat;
    ui.click.chat = function () {
        var chatResult = originalChat.apply(this, arguments);
        if (!chatResult) return chatResult;

        setTimeout(function () {
            injectClskEmotions(chatResult);
        }, 10);
        return chatResult;
    };
    lib.message.client["clsk_emotion"] = function (pid, packId, fileName) {
        var player = lib.playerOL[pid];
        if (!player && game.connectPlayers) {
            for (var i = 0; i < game.connectPlayers.length; i++) {
                if (game.connectPlayers[i].playerid === pid) {
                    player = game.connectPlayers[i];
                    break;
                }
            }
        }
        if (!player) return;
        var pack = CLSK_Emotion.cache[packId];
        if (!pack) return;
        var imgSrc = lib.assetURL + pack.path + fileName;
        var html = '<img src="' + imgSrc + '" width="90" height="90" onerror="this.outerHTML=\'[表情]\'">';
        player.say(html);
    };
}

function injectClskEmotions(uiintro) {
    if (uiintro._clsk_emotion_injected) return;
    uiintro._clsk_emotion_injected = true;
    var chatContainer = uiintro.contentContainer || uiintro.content;
    if (!chatContainer) return;
    var allScrollDivs = chatContainer.querySelectorAll('div[style*="overflow: scroll"]');
    var packList = allScrollDivs[1];
    if (!packList) return;

    var bindAllTitles = function() {
        var allCenterTitles = chatContainer.querySelectorAll('.text.center');
        allCenterTitles.forEach(function(title) {
            if (title._hasClskEmotionBind) return;
            title._hasClskEmotionBind = true;

            var originalClick = title.onclick;

            var handler = function(e) {
                CLSK_Emotion_TitleClick(uiintro, packList);
                if (originalClick) originalClick.call(this, e);
                if (e && e.preventDefault) e.preventDefault();
            };

            title.onclick = handler;
            title.ontouchstart = handler;
        });
    };

    bindAllTitles();

    // 渲染表情包按钮
    var packIds = Object.keys(CLSK_Emotion.cache);
    for (var i = 0; i < packIds.length; i++) {
        var pack = CLSK_Emotion.cache[packIds[i]];
        var firstImg = pack.files[0];
        var firstImgPath = lib.assetURL + pack.path + firstImg;
        var packButton = ui.create.div(".card.fullskin",
            '<img src="' + firstImgPath + '" width="50" height="50" onerror="this.outerHTML=\'' + pack.name + '\'">',
            function () {
                showEmotionDetail(uiintro, this.pack);
            }
        );
        packButton.pack = pack;
        packButton.style.cssText = "height:50px;width:50px;margin:2px;display:inline-block;";
        packList.appendChild(packButton);
    }
    setTimeout(bindAllTitles, 50);
}

function showEmotionDetail(uiintro, pack) {
    var chatContainer = uiintro.contentContainer || uiintro.content;
    var allScrollDivs = chatContainer.querySelectorAll('div[style*="overflow: scroll"]');
    var packList = allScrollDivs[1];

    if (CLSK_Emotion.currentDetailPanel) {
        CLSK_Emotion.currentDetailPanel.remove();
    }

    var detailList = ui.create.div("");
    CLSK_Emotion.currentDetailPanel = detailList;
    var height = get.is.phoneLayout() ? "110px" : "150px";
    detailList.style.cssText = "height:" + height + ";overflow:scroll;";
    lib.setScroll(detailList);
    uiintro.add(detailList);
    detailList.innerHTML = "";

    for (var i = 0; i < pack.files.length; i++) {
        (function (pack, fileName, index) {
            var imgSrc = lib.assetURL + pack.path + fileName;
            var img = new Image();
            img.onload = function () {
                var emotionBtn = ui.create.div(".card.fullskin",
                    '<img src="' + imgSrc + '" width="50" height="50" onerror="this.outerHTML=\'×\'">',
                    function () {
                        sendClskEmotion(pack.id, fileName);
                        if (uiintro.hide) uiintro.hide();
                        ui.system1.classList.remove("shown");
                        ui.system2.classList.remove("shown");
                    }
                );
                emotionBtn.style.cssText = "height:50px;width:50px;margin:2px;display:inline-block;";
                detailList.appendChild(emotionBtn);
            };
            img.onerror = function () {
                var errorBtn = ui.create.div(".card.fullskin",
                    '<div style="width:50px;height:50px;line-height:50px;text-align:center;font-size:12px;background:#f44;color:white;">' + (index + 1) + '</div>'
                );
                errorBtn.style.cssText = "height:50px;width:50px;margin:2px;display:inline-block;";
                detailList.appendChild(errorBtn);
            };
            img.src = imgSrc;
        })(pack, pack.files[i], i);
    }

    var allTitles = chatContainer.querySelectorAll('.text.center');
    if (allTitles.length === 1) {
        allTitles[0].innerHTML = pack.name;
    } else {
        allTitles.forEach((title, index) => {
            if (index === 0) {
                title.innerHTML = "无聊天记录";
            } else {
                title.innerHTML = pack.name;
            }
        });
    }

    if (packList) packList.style.display = "none";
    uiintro.add(detailList);
    uiintro.style.height = uiintro.content.scrollHeight + "px";
}

function sendClskEmotion(packId, fileName) {
    var player = game.me;
    if (!player && game.connectPlayers) {
        if (game.online) {
            for (var i = 0; i < game.connectPlayers.length; i++) {
                if (game.connectPlayers[i].playerid === game.onlineID) {
                    player = game.connectPlayers[i];
                    break;
                }
            }
        } else {
            player = game.connectPlayers[0];
        }
    }
    if (!player) return;
    var pack = CLSK_Emotion.cache[packId];
    if (!pack) return;
    var imgSrc = lib.assetURL + pack.path + fileName;
    var html = '<img src="' + imgSrc + '" width="90" height="90" onerror="this.outerHTML=\'[表情]\'">';
    player.say(html);
    game.broadcast("clsk_emotion", player.playerid, packId, fileName);
}

function initClskEmotion() {
    if (CLSK_Emotion.initialized) return;
    CLSK_Emotion.initialized = true;
    loadClskEmotions();
    setTimeout(function () {
        enhanceChatUI();
    }, 300);
}

if (document.readyState === "complete") {
    initClskEmotion();
} else {
    window.addEventListener("load", initClskEmotion);
}

lib.onprepare.push(function () {
    initClskEmotion();
});

