lib.snowEffect = (function() {
   const snow = {
     ctx: null,
     canvas: null,
     snowflakes: [],
     count: 60, 
     init: function(isBroadcast = false) {
       if (!isBroadcast) {
         game.broadcastAll(function() {
           lib.snowEffect.init(true);
         });
       }
       if (document.getElementById('snowCanvas')) return;
       // 强制插入body最顶层，确保覆盖全屏幕
       const canvas = document.createElement('canvas');
       canvas.id = 'snowCanvas';
       canvas.style.cssText = `
         position: fixed; top: 0; left: 0; width: 100%; height: 100%;
         pointer-events: none; z-index: 99999; opacity: 0.8;
         margin: 0; padding: 0; border: none;
       `;
       document.body.appendChild(canvas);
       snow.canvas = canvas;
       snow.ctx = canvas.getContext('2d');
       
       // 强制铺满屏幕（忽略任何容器限制）
       snow.resize();
       window.addEventListener('resize', snow.resize);
       new ResizeObserver(snow.resize).observe(document.body);
       
       snow.createSnowflakes();
       snow.animate();
     },
     resize: function() {
       if (!snow.canvas) return;
       // 强制设置为屏幕实际尺寸，不受布局影响
       snow.canvas.width = window.innerWidth;
       snow.canvas.height = window.innerHeight;
       // 清除原有雪花，重新生成（确保覆盖新尺寸）
       snow.createSnowflakes();
     },
     createSnowflakes: function() {
       snow.snowflakes = [];
       const width = snow.canvas.width;
       const height = snow.canvas.height;
       // 生成范围扩大10%，避免边缘空白
       const extendW = width * 0.1;
       const extendH = height * 0.1;
       
       for (let i = 0; i < snow.count; i++) {
         snow.snowflakes.push({
           x: Math.random() * (width + extendW * 2) - extendW, // 左右各延伸10%
           y: Math.random() * (height + extendH) - extendH, // 上方延伸10%
           radius: Math.random() * 4 + 1, // 雪花变大（1-5px）
           speedY: Math.random() * 3 + 1.5, // 下落速度加快（1.5-4.5px/帧）
           speedX: Math.random() * 2 - 1, // 左右飘动范围扩大（-1~1px/帧）
           opacity: Math.random() * 0.7 + 0.2
         });
       }
     },
     animate: function() {
       if (!snow.ctx) return;
       snow.ctx.clearRect(0, 0, snow.canvas.width, snow.canvas.height);
       
       snow.snowflakes.forEach(flake => {
         snow.ctx.beginPath();
         snow.ctx.arc(flake.x, flake.y, flake.radius, 0, Math.PI * 2);
         snow.ctx.fillStyle = `rgba(255, 255, 255, ${flake.opacity})`;
         snow.ctx.fill();
         
         // 加速下落+飘动，减少空白感
         flake.y += flake.speedY;
         flake.x += flake.speedX;
         
         // 超出屏幕立即重置（无延迟补位）
         const width = snow.canvas.width;
         const height = snow.canvas.height;
         if (flake.y > height + 20 || flake.x < -20 || flake.x > width + 20) {
           flake.y = Math.random() * -50;
           flake.x = Math.random() * width;
         }
       });
       
       requestAnimationFrame(snow.animate);
     },
     destroy: function(isBroadcast = false) {
       if (!isBroadcast) {
         game.broadcastAll(function() {
           lib.snowEffect.destroy(true);
         });
       }
       if (snow.canvas) {
         snow.canvas.remove();
         window.removeEventListener('resize', snow.resize);
       }
       snow.snowflakes = [];
       snow.ctx = null;
       snow.canvas = null;
     }
   };
   return snow;
 })();
 
 //轮回乐园
 lib.sakuraEffect = (function() {
   const sakura = {
     ctx: null,
     canvas: null,
     petals: [],
     count: 80, 
     init: function(isBroadcast = false) {
       if (!isBroadcast) {
         game.broadcastAll(function() {
           lib.sakuraEffect.init(true);
         });
       }
       if (document.getElementById('sakuraCanvas')) return;
       const canvas = document.createElement('canvas');
       canvas.id = 'sakuraCanvas';
       canvas.style.cssText = `
         position: fixed; top: 0; left: 0; width: 100%; height: 100%;
         pointer-events: none; z-index: 99999; opacity: 0.9;
         margin: 0; padding: 0; border: none;
       `;
       document.body.appendChild(canvas);
       sakura.canvas = canvas;
       sakura.ctx = canvas.getContext('2d');
       
       sakura.resize();
       window.addEventListener('resize', sakura.resize);
       new ResizeObserver(sakura.resize).observe(document.body);
       
       sakura.createPetals();
       sakura.animate();
     },
     resize: function() {
       if (!sakura.canvas) return;
       sakura.canvas.width = window.innerWidth;
       sakura.canvas.height = window.innerHeight;
       sakura.createPetals();
     },
     createPetals: function() {
       sakura.petals = [];
       const width = sakura.canvas.width;
       const height = sakura.canvas.height;
       const extendW = width * 0.15;
       const extendH = height * 0.15;
       
       for (let i = 0; i < sakura.count; i++) {
         sakura.petals.push({
           x: Math.random() * (width + extendW * 2) - extendW,
           y: Math.random() * (height + extendH) - extendH,
           size: Math.random() * 5 + 2, // 花瓣大小
           speedY: Math.random() * 2 + 1, // 下落速度
           speedX: Math.random() * 3 - 1.5, // 斜向速度（控制飘落角度）
           opacity: Math.random() * 0.6 + 0.3,
           rotation: Math.random() * Math.PI * 2, // 旋转角度
           rotationSpeed: (Math.random() - 0.5) * 0.1 // 旋转速度
         });
       }
     },
     animate: function() {
       if (!sakura.ctx) return;
       sakura.ctx.clearRect(0, 0, sakura.canvas.width, sakura.canvas.height);
       
       sakura.petals.forEach(petal => {
         // 绘制发光花瓣
         sakura.ctx.save();
         sakura.ctx.translate(petal.x, petal.y);
         sakura.ctx.rotate(petal.rotation);
         
         // 发光效果
         sakura.ctx.shadowBlur = 10;
         sakura.ctx.shadowColor = 'rgba(255, 255, 255, 0.8)';
         sakura.ctx.fillStyle = `rgba(255, 255, 255, ${petal.opacity})`;
         
         // 花瓣形状（五瓣花）
         sakura.ctx.beginPath();
         for (let j = 0; j < 5; j++) {
           const angle = (j * 2 * Math.PI) / 5;
           const r = j % 2 === 0 ? petal.size : petal.size * 0.6;
           const px = r * Math.cos(angle);
           const py = r * Math.sin(angle);
           if (j === 0) sakura.ctx.moveTo(px, py);
           else sakura.ctx.lineTo(px, py);
         }
         sakura.ctx.closePath();
         sakura.ctx.fill();
         
         sakura.ctx.restore();
         
         // 更新位置和旋转
         petal.y += petal.speedY;
         petal.x += petal.speedX;
         petal.rotation += petal.rotationSpeed;
         
         // 超出屏幕重置
         const width = sakura.canvas.width;
         const height = sakura.canvas.height;
         if (petal.y > height + 30 || petal.x < -30 || petal.x > width + 30) {
           petal.y = Math.random() * -50;
           petal.x = Math.random() * width;
         }
       });
       
       requestAnimationFrame(sakura.animate);
     },
     destroy: function(isBroadcast = false) {
       if (!isBroadcast) {
         game.broadcastAll(function() {
           lib.sakuraEffect.destroy(true);
         });
       }
       if (sakura.canvas) {
         sakura.canvas.remove();
         window.removeEventListener('resize', sakura.resize);
       }
       sakura.petals = [];
       sakura.ctx = null;
       sakura.canvas = null;
     }
   };
   return sakura;
 })();
    
