game._originalOver = game.over;
game.myOverLogic = async function myOverLogic() {
   const KuiPlayers = game.filterPlayer(current => current.name === "奎隆一");
   if (KuiPlayers.length === 0) {
     return false; 
   }
   const Kui = KuiPlayers[0]; 
   const hasEnemy = game.hasPlayer(current => {
     return get.attitude(Kui,current) <= 0; 
   });
   const KuisayPlayers = game.filterPlayer(current => get.translation(current) =="奎隆，摩诃萨埵权化");
  if(KuisayPlayers.length>0)game.tis3("<font color=#00ffff>莲瓣入水而不苦根茎，施主，勿执着！</font>",7000);
  if (hasEnemy) {
    game.playAudio('..', 'extension', '错乱时空', '音频', '呼吸法1.mp3');
    Kui.cs1s("<font color=#f00>不得所愿，皆因欲求</font>；欲无尽，则是<font color=#f00>妄</font>，求不止，尽为<font color=#f00>伤</font>",7);
    return true; 
  }
  return false; 
}
