    lib.element.player.soulDamage=function(){
        var next = game.createEvent('soulDamage');
		next.player = this;
		for (var i = 0; i < arguments.length; i++) {
			if (typeof arguments[i] == 'number') {
				next.num = arguments[i];
			}else if(get.itemtype(arguments[i])=="player"){
			    next.source=arguments[i];
			}
		}
		if (!next.source && !noSource) {
        const source = event.customSource || event.player;
        if (source && !source.isDead()) next.source = source;
    }
		if (!next.num) next.num = 1;
        next.setContent('soulDamage');
		return next;
    };
    lib.element.content.soulDamage=function(){
        if(typeof player.maxsoulhp!='number'){
            player.maxsoulhp=player.maxHp;
        }
        if(typeof player.soulhp!='number'){
            player.soulhp=player.maxsoulhp;
        }
        player.damage(num,'soul','unreal',source);
        event.trigger("changeSoulHp");
        player.soulhp-=num;
        if(player.soulhp<=0){
            player.hp=player.soulhp;
            player.update();
            player.dying();
        }
    };
    lib.element.player.soulRecover=function(){
        var next = game.createEvent('soulRecover');
		next.player = this;
		for (var i = 0; i < arguments.length; i++) {
			if (typeof arguments[i] == 'number') {
				next.num = arguments[i];
			}
		}
		if (!next.num) next.num = 1;
        next.setContent('soulRecover');
		return next;
    };
    lib.element.content.soulRecover=function(){
        if(typeof player.maxsoulhp!='number'){
            player.maxsoulhp=player.maxHp;
        }
        if(typeof player.soulhp!='number'){
            player.soulhp=player.maxsoulhp;
        }
        var xs=player.maxsoulhp-player.soulhp;
        if(num<=xs){
            player.$damagepop(num,'green');
        }else{
            player.$damagepop(xs,'green');
        }
        event.trigger("changeSoulHp");
        player.soulhp+=num;
        if(player.soulhp-player.maxsoulhp>0){
            player.soulhp=player.maxsoulhp;
        }
    };
