//构筑
function cl_gouzhuFilter(card, player, cards, costs,max){
if(max&&cards.length>=max)return false;
//先判断有没有满足任意costs条件的，都不满足就直接否掉。
for(var i=0;i<costs.length;i++){
if(costs[i].filter(card)) break;
if(i==(costs.length-1)) return false;
}
//把这张牌丢进已选牌里面去，进行二次验证操作。
var list=cards.slice(0);
list.push(card);
//创建一个对象，用来记录核验结果。
var map=[];
map.length=costs.length;
map.fill(0);
//根据满足项数的多少进行排序，先把只满足一项的处理掉，满足多项挨个分类，到时候依次填进去，避免满足多项的先占掉位置后，导致单项的没位置。
list.sort((a,b)=>{
var numa=0,numb=0;
for(var cost of costs){
if(cost.filter(a)) numa++;
if(cost.filter(b)) numb++;
}
return numa-numb;
})
//把每一张已选择的牌，分配到对应的条件里面去。
for(var i of list){
var bool=false;
for(var j=0;j<costs.length;j++){
if(costs[j].filter(i)&&(costs[j].num||1)>map[j]){
map[j]++;
bool=true;
break;
}
}
if(!bool)return false;
}
return true;
}
