            "天雷":{
                audio:"ext:错乱时空:2",
                audioname:["boss_qinglong"],
                trigger:{
                    player:["useCard","respond"],
                },
                filter:function (event,player){
        return event.card.name=='sha';
    },
                direct:true,
                content:function (){
        "step 0";
        player.chooseTarget(get.prompt2('天雷'),function(card,player,target){
         return target!=player;
        }).ai=function(target){
            if(target.hasSkill('hongyan')) return 0;
            return get.damageEffect(target,_status.event.player,_status.event.player,'thunder');
        };
        "step 1"
        if(result.bool){
            player.logSkill('天雷',result.targets,'thunder');
            event.target=result.targets[0];
            event.target.judge(function(card){
                var suit=get.suit(card);
                if(suit=='spade') return -4;
                if(suit=='club') return -2;
                if(suit=='diamond') return -3;
                return 0;
            });
        }
        else{
            event.finish();
        }
        "step 2"
        if(result.suit=='club'){
            event.target.damage(2,'thunder');
            player.recover();
        }
        else if(result.suit=='spade'){
            event.target.damage(3,'thunder');
        }
        else if(result.suit=='diamond'){
            event.target.damage('thunder');
            player.draw(2);
        }
    },
                ai:{
                    useSha:true,
                    effect:{
                        target:function (card,player,target,current){
                if(get.tag(card,'respondSha')){
                    var hastarget=game.hasPlayer(function(current){
                        return get.attitude(target,current)<0;
                    });
                    var be=target.countCards('e',{color:'black'});
                    if(target.countCards('h','sha')&&be){
                        if(!target.hasSkill('神旨')) return 0;
                        return [0,hastarget?target.countCards('he')/2:0];
                    }
                    if(target.countCards('h','sha')&&target.countCards('h')>2){
                        if(!target.hasSkill('神旨')) return 0;
                        return [0,hastarget?target.countCards('h')/4:0];
                    }
                    if(target.countCards('h')>3||(be&&target.countCards('h')>=2)){
                        return [0,0];
                    }
                    if(target.countCards('h')==0){
                        return [1.5,0];
                    }
                    if(target.countCards('h')==1&&!be){
                        return [1.2,0];
                    }
                    if(!target.hasSkill('神旨')) return [1,0.05];
                    return [1,Math.min(0.5,(target.countCards('h')+be)/4)];
                }
            },
                    },
                },
            },
