                position:"he",
                content:function (){
       'step 0'
    
        var diamond = 0;
        var heart = 0;
        var spade = 0;
        var club = 0;
        for(var i=0;i<event.cards.length;i++){
            var suit = get.suit(event.cards[i]);
            if(suit == 'diamond'){
                diamond = 1;
            }
            if(suit == 'heart'){
                heart = 1;
            }
            if(suit == 'spade'){
                spade = 1;
            }
            if(suit == 'club'){
                club = 1;
            }
        }
             event.rhjycount =diamond+heart+spade+club;
        player.chooseTarget([1,event.rhjycount],get.prompt('熔核巨影'),'对x名其他角色造成1点伤害',function(card,player,target){
            return target!=player;
        }).set('ai',function(target){
            var player=_status.event.player;
            return get.damageEffect(target,player,player);
        });
        'step 1'
        if(result.bool){
            player.logSkill('熔核巨影',result.targets);
            event.targets=result.targets;
            event.num=0;
            }
           'step 2' 
        if(event.num<event.targets.length){
            var k=1+Math.floor(event.rhjycount/2);
            
           if(result.targets=1) event.targets[event.num].damage(k,'fire');
           if(result.targets>1) event.targets[event.num].damage(1,'fire');
            event.num++;
            event.redo();
        
            
        }
 },
