                content:function (){
        "step 0"
        player.loseHp();
        target.chooseControl('令流形随机获得你一个技能','令流形获得你一点体力上限').set('ai',function(event,player){
            if(get.attitude(player,event.player)>0)return '令流形随机获得你一个技能';
            return '令流形获得你一点体力上限';
        });
        "step 1"
            var lgroup=target.group;
            var lmale=target.sex;
            var lmaxHp=target.maxHp-1>0?target.maxHp-1:1;
            if(result.control=='令流形获得你一点体力上限'){
                target.loseMaxHp();
                lmaxHp+=1;
            }
            var lhp=target.hp-1>0?target.hp-1:1;
            var targets=game.filterPlayer(current => {
                    return current==target;
            })
            var cards = targets.map(i => i.getCards("h"))
            //i：循环变量，代表当前遍历的每个targets
            // i.getCards("h")：获取该targets玩家的“手牌”
                    .flat()
            // .flat()：将“每个玩家的手牌列表”组成的二维列表（如 [[卡1,卡2], [卡3]]），扁平化为一维列表（如 [卡1,卡2,卡3]），方便后续统一筛选
                    .filter(card => {
                        return !player.getCards("s").map(i => i._cardid).includes(card.cardid);
                    });
                var cardsx = cards.map(card => {
                    var cardx = ui.create.card();
                    cardx.init(get.cardInfo(card));
                    cardx._cardid = card.cardid;
                    return cardx;
                });
            var list=[];
            if(result.control=='令流形随机获得你一个技能'){
                var skills=target.getSkills(true,false);
                for(var i=0;i<skills.length;i++){
                 list.push(skills[i]);
            }
            }
            if(list.length<1)list.push('冲锋');
            var b=list.randomGet();
            var skill=player.addSubPlayer({
                name:'流形',
                group:lgroup,
                sex:lmale,
                skills:[b,'流形_exit','流形_enter'],
                hp:lhp,
                maxHp:lmaxHp,
                hs:cardsx,
                skill:skill,
                intro2:'当前回合结束后进行一个额外回合',
                onremove:function(player){
                    player.storage.流形.remove(skill);
                    delete lib.skill[skill];
                }
            }
            );
            player.storage.流形.push(skill);
            var name = skill;
        lib.character[name][4].remove("character:流形");
        lib.character[name][4].push("ext:错乱时空/流形.jpg");
    },
