                position:"h",
                filterCard:true,
                filterTarget:true,
                filter:function(event,player){
                return player.countCards('h')>=2;
                },
                content:function(){
                    var num=0;
                    var trick=0;
                    var basic=0;
                    var equip=0;
                    var newcard=get.cards();
                    game.cardsGotoOrdering(newcard);
                    player.showCards(newcard,'厨道');
                    switch(get.type(newcard[0])){
                     case 'basic':
                     basic++;
                     break;
                     
                     case 'trick':
                     trick++;
                     break;
                     
                     case 'equip':
                     equip++;
                     break;
                     
                     default:
                     game.log("似乎是不能吃的东西");
                    }
                    for(var i of cards){
                    if(get.type(i)=='basic')basic++;
                    if(get.type(i)=='trick')trick++;
                    if(get.type(i)=='equip')equip++;
                    };
                    if(trick==3||basic==3||equip==3){
                        num=3;
                    }else if(trick==2||basic==2||equip==2){
                        num=2;
                    }else if(trick==1||basic==1||equip==1){
                        num=1;
                    };
                    switch(num){
                        case 1:
                        for(var j of targets){
                    j.recover();
                    j.draw(2);
                        };
                        break;
                        
                        case 2:
                        for(var j of targets){
                    j.draw(1);
                        };
                        break;
                        
                        case 3:
                        for(var j of targets){
                    j.recover(2);
                    j.draw(1);
                        };
                        break;
                        
                        default:
                        game.log("下厨失败");
                    };
                },
