            "_音乐锁":{
                trigger:{player:'phaseBefore'},
                forced:true,
                direct:true,
                firstDo:true,
                priority:1000,
                filter:function(event,player){
                  if(!player.name||game.clsk_bgm) return;
                  if(game.clsk_cbgm.includes(player.name))return true;
                },
             content:function(){
                 if(player.name=="庄方宜"){
                    game.broadcastAll(function (player) {
                ui.backgroundMusic.src=lib.assetURL+'extension/错乱时空/音频/观陵水.mp3';
                ui.backgroundMusic.loop = true;
                game.clsk_bgm=true;
            }, player);
                 }
             },
            },
            "_武将锁":{
                trigger:{global:['gameDrawAfter'],player:'enterGame'},
                forced:true,
                direct:true,
                firstDo:true,
                priority:1000,
                filter:function(event,player){
                  if (!player.name) return;
                  if(!_status.connectMode)return;
                  var character = lib.clsk_jswj_character;
                  for (var i in character) {
  if (player.name === i) {
                        return true;
                     }
                  }
                },
            content:function(){
                var character = lib.clsk_jswj_character;
                window.clskDataMap = window.clskDataMap || {};
                //alert(`所有信息（供验证）：${JSON.stringify(window.clskDataMap)}`);
                const currentOnlineID = player.nickname;
                const dataSource = window.clskDataMap[currentOnlineID] || {}; 
              for (var i in character) {
               if (player.name === i) {
                     const targetData = dataSource[i];                    
                     if(targetData){
                      for(var s of lib.clsk_jswj_character[i].info[3]){
         player.addSkill(s);
      }
                const parts = (lib.clsk_jswj_character[i].info[2] + '').split('/').map(Number).filter(n => !isNaN(n));
      if(parts.length>=3)player.hujia=parts[2];
      if(parts.length>=2){
         player.maxHp=parts[1];
         player.hp=parts[0];
      }else{
         player.maxHp=parts[0];
         player.hp=parts[0];
      }
                     }else{
                       player.skills = [];
                       player.maxHp=1;
                       player.hp=0;
                     }
             player.update();
             if(typeof dataSource[i+'_mingzuo']=="number"&&dataSource[i+'_mingzuo']>1){
                        var a=dataSource[i+'_mingzuo'];
                        game.broadcastAll(function(i,a) {
                       lib.config.clsk_jswj[i+'_mingzuo']=a;
                    },i,a);
                     }
                  }
                }
             },
            },
