            _qimanzhilong:{
    trigger:{
        player:["chooseToRespondBegin","chooseToUseBegin"],
    },
    forced:true,
    popup:false,
    max:5,
    filter:function(event,player){
        return lib.config.mode=='肉鸽模式'&&game.buff.includes('欺瞒之龙')&&event.player.identity=='friend'&&_status.currentPhase!=player;
    },
    priority:101,
    content:function(){
        var cards=[];
        var max=Math.min(ui.cardPile.childNodes.length,lib.skill._qimanzhilong.max);
        for(var i=0;i<max;i++){
            var card=ui.cardPile.childNodes[i];
            if(trigger.filterCard(card,player,trigger)){
                cards.push(card);
            }
        }
        if(cards.length){
            player.gain(cards,'draw');
            player.logSkill('_qimanzhilong');
            game.log(player,'获得了'+get.cnNumber(cards.length)+'张牌');
        }
    },
    ai:{
        respondSha:true,
        respondShan:true,
        effect:{
            target:function(card,player,target,effect){
                if(get.tag(card,'respondShan')) return 0.7;
                if(get.tag(card,'respondSha')) return 0.7;
            },
        },
    },
    hiddenCard:function(player,name){
        if(_status.currentPhase==player||lib.config.mode!='肉鸽模式'||!game.buff.includes('欺瞒之龙')||player.identity!='friend')return false;
        var max=Math.min(ui.cardPile.childNodes.length,lib.skill._qimanzhilong.max);
        for(var i=0;i<max;i++){
            var card=ui.cardPile.childNodes[i];
            if(card.name==name) return true;
        }
        return false;
    },
    "_priority":10100,
},
