			        xround:function(){
			            //新的一轮
			            "step 0"
			            game.delay(0.5);
			            "step 1"
for(var i=0;i<game.players.length;i++){
             if(game.players[i].side) continue;
            game.players[i].removeEquipTrigger();
            var hej=game.players[i].getCards('hej');
            for(var j=0;j<hej.length;j++){
                hej[j].discard(false);
            }
            game.players[i].hp=game.players[i].maxHp;
            game.players[i].hujia=0;
            game.players[i].classList.remove('turnedover');
            game.players[i].removeLink();
            game.players[i].enableEquip(1);
            game.players[i].enableEquip(2);
            game.players[i].enableEquip(3);
            game.players[i].enableEquip(4);
            game.players[i].enableEquip(5);
            var mop=4;
            if(game.buff.includes("群山的赠予"))mop+=3;
            game.players[i].directgain(get.cards(mop));
        }
        "step 2"
        while(_status.event.name!='phase'){
            _status.event=_status.event.parent;
        }
        game.resetSkills();
        _status.paused=false;
        if(_status.event.player!=game.me)_status.event.player=game.me;
        _status.event.step=0;
        _status.roundStart=game.me;
        game.phaseNumber=0;
        game.roundNumber=0;
			        },
			        jiaqiang:function(){
			            //加强角色
			            for(var i=0;i<game.players.length;i++){
			              if(game.players[i].identity=='enemy'){
			game.players[i].maxHp*=game.schedule;
			game.players[i].maxHp+=(game.schedule*game.matter);
			game.players[i].hp=game.players[i].maxHp;
			game.players[i].update();
			              };
			              if(game.buff.includes('象神伟力')&&game.players[i].identity=='friend'){
			game.players[i].maxHp+=5;
			game.players[i].update();
			              }
			              if(game.buff.includes('象神伟力-扭曲')&&game.players[i].identity=='friend'){
			game.players[i].maxHp-=1;
			game.players[i].update();
			              }
			              if(game.buff.includes('群山的赠予')&&game.players[i].identity=='friend'){
			game.players[i].maxHp+=4;
			game.players[i].update();
			              }
			              if(game.buff.includes('群山的赠予-扭曲')&&game.players[i].identity=='friend'){
			game.players[i].maxHp+=8;
			game.players[i].update();
			              }
			              if(game.buff.includes('群山的呼唤')&&game.players[i].identity=='friend'){
			game.players[i].maxHp+=8;
			game.players[i].update();
			              }
			              if(game.buff.includes('群山的呼唤-扭曲')&&game.players[i].identity=='enemy'){
			game.players[i].maxHp=Math.ceil(game.players[i].maxHp*1.5);
			game.players[i].update();
			              }
			              if(game.buff.includes('怒吼之龙')&&game.players[i].identity=='enemy'){
			game.players[i].maxHp=Math.ceil(game.players[i].maxHp*0.5);
			game.players[i].update();
			              }
			              if(game.buff.includes('怒吼之龙-扭曲')){
			if(game.players[i].identity=='enemy')game.players[i].maxHp=Math.ceil(game.players[i].maxHp*0.4);
			if(game.players[i].identity=='friend')game.players[i].maxHp=Math.ceil(game.players[i].maxHp*0.6);
			game.players[i].update();
			              }
			              if(game.buff.includes('达贡的金沙-扭曲')&&game.players[i].identity=='enemy'&&game.players[i].name.indexOf('宝箱')>=0){
			game.players[i].maxHp=Math.ceil(game.players[i].maxHp*3);
			game.players[i].update();
			              }
			              if(game.rare>1&&game.players[i].identity=='enemy'){
			game.players[i].maxHp=Math.ceil(game.players[i].maxHp*1.3);
			game.players[i].update();
			              }
			              if(game.buff.includes('至尊至高之龙-扭曲')&&game.players[i].identity=='friend'){
			game.players[i].maxHp=1;
			game.players[i].skills.push('dieyuan2');
			game.players[i].update();
			game.buff.remove('至尊至高之龙-扭曲');
			              }
			            }
			        },
