			        wujianganniu:function(item,type,position,noclick,node){
			     //商店里的武将按钮
					node=ui.create.buttonPresets.character(item,'character',position,noclick);
					const info=lib.character[item];
					var p=5000;
					if(game.price[item])p=game.price[item];
					if(game.buff.includes("豪横之龙"))p=Math.floor(p*0.7);
					if(game.buff.includes("豪横之龙-扭曲")){
					    p=Math.ceil(p*0.25);
					    p=Math.ceil(p*game.haohengzhilongN);
					}
					if(game.buff.includes("蛮横之金龙"))p=Math.floor(p*0.1);
					if(game.buff.includes("蛮横之金龙-扭曲"))p*=5;
						const skillstr="<span class=yellowtext>"+p+"</span>";
						const skillnode=ui.create.caption(
							`<div class="text" data-nature=${get.groupnature(info[1],'raw')
								}m style="font-family: ${(lib.config.name_font||'xinwei')
								},xinwei">${skillstr}</div>`,node);
						skillnode.style.left='2px';
						skillnode.style.bottom='2px';
					
					return node;
				},
