            var kobimodeContent={//具体内容
                mode:'科比之心',
                start:function(){//游戏开始
                    'step 0'
                    var playback=localStorage.getItem(lib.configprefix+'playback');
        			if(playback){
        				ui.create.me();
        				ui.arena.style.display='none';
        				ui.system.style.display='none';
        				_status.playback=playback;
        				localStorage.removeItem(lib.configprefix+'playback');
        				var store=lib.db.transaction(['video'],'readwrite').objectStore('video');
        				store.get(parseInt(playback)).onsuccess=function(e){
        					if(e.target.result){
        						game.playVideoContent(e.target.result.video);
        					}else{
        						alert('播放失败：找不到录像');
        						game.reload();
        					};
        				};
        				event.finish();
        			}else if(!_status.connectMode){
        				game.prepareArena(1);
        			};
        			'step 1'
        			_status.mode='科比之心';
        			alert("将军，科比邀您到直升机上一叙，仪表未必为真，请务必保持螺旋桨转动。");
        			
        			'step 2'
        			for(var i=0;i<game.players.length;i++){
        					game.players[i].getId();
        		    }
        		    game.me.init('Mon3tr');
        		    game.me.node.avatar.setBackgroundImage('extension/错乱时空/魔科比.jpg');
        		    game.me.name="魔科比",
        		    game.me.name1="魔科比",
        		    game.me.node.name.innerHTML="魔科比"
        		    game.me.update();
        		    game.me.clearSkills();
        		    game.me.addSkill("科比之心");
        		    
        		    'step 3'
        		    if(ui.coin)_status.coinCoeff=get.coinCoeff([game.me.name]);
        			game.syncState();
        			event.trigger('gameStart');
        			_status.videoInited=true;
        			game.gameDraw(game.me);
        			if(_status.connectMode&&lib.configOL.change_card)game.replaceHandcards(game.players.slice(0));
        			game.phaseLoop(game.me);
        	        alert("通过游玩小游戏获得更高的分数来解锁武将");
        	        alert("牢  牢记住，逝者为  大");
        	    },
            };
            game.addMode('科比之心',kobimodeContent,kobimodeConfig);
